"use server";

import { createClient } from "@/lib/supabase/server";
import { revalidatePath } from "next/cache";

export async function saveActivity(formData: any, categoryId: string) {
  const supabase = await createClient();

  const { data: { session } } = await supabase.auth.getSession();
  if (!session) throw new Error("Not authenticated");

  const startDateTime = formData.isAllDay 
    ? `${formData.date}T00:00:00` 
    : `${formData.date}T${formData.time}:00`;

  let endDateTime = null;
  if (!formData.isAllDay && formData.endTime) {
    endDateTime = `${formData.date}T${formData.endTime}:00`;
  }

  const payload = {
    title: formData.title,
    description: formData.description,
    whatsapp_link: formData.whatsapp_link || null,
    subcategory_id: formData.subcategory_id || null,
    category_id: categoryId,
    start_datetime: startDateTime,
    end_datetime: endDateTime,
    location: formData.location,
    location_coords: formData.location_coords || null,
    metadata: {
      distance: formData.distance,
      elevation: formData.elevation,
      difficulty: formData.difficulty,
      isAllDay: formData.isAllDay,
      isLocked: formData.isLocked || false,
      unlockAt: formData.unlockAt || null
    },
    status: 'published'
  };

  let error;
  if (formData.id) {
    const { error: updateError } = await supabase.from("move_activities").update(payload).eq("id", formData.id);
    error = updateError;
  } else {
    const { error: insertError } = await supabase.from("move_activities").insert(payload);
    error = insertError;
  }

  if (error) {
    console.error("Error saving activity:", error);
    return { success: false, error: error.message };
  }

  revalidatePath("/v/[token]/move", "page");
  return { success: true };
}

export async function deleteActivity(id: string) {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();
  if (!session) throw new Error("Not authenticated");

  const { error } = await supabase.from("move_activities").delete().eq("id", id);
  if (error) return { success: false, error: error.message };

  revalidatePath("/v/[token]/move", "page");
  return { success: true };
}

export async function geocodeLocation(query: string) {
  try {
    const res = await fetch(`https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(query)}&format=json&limit=1&addressdetails=1`, {
      method: "GET",
      headers: {
        "Accept-Language": "ca,es,en",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
      }
    });

    if (!res.ok) return { success: false, error: `HTTP ${res.status}` };

    const data = await res.json();
    if (Array.isArray(data) && data.length > 0) {
      return { success: true, lat: data[0].lat, lng: data[0].lon, display_name: data[0].display_name };
    }
    return { success: false, error: "No s'ha trobat res" };
  } catch (e) {
    console.error("Geocode error:", e);
    return { success: false, error: "Error de xarxa" };
  }
}

export async function reverseGeocode(lat: number, lng: number) {
  try {
    const res = await fetch(`https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json&addressdetails=1`, {
      method: "GET",
      headers: {
        "Accept-Language": "ca,es,en",
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
      }
    });

    if (!res.ok) return { success: false, error: `HTTP ${res.status}` };

    const data = await res.json();
    if (data && data.display_name) {
      return { success: true, address: data.display_name };
    }
    return { success: false, error: "Adreça no trobada" };
  } catch (e) {
    console.error("Reverse geocode error:", e);
    return { success: false, error: "Error de xarxa" };
  }
}

"use server";

import { createClient } from "@/lib/supabase/server";
import { createClient as createSupabaseClient } from "@supabase/supabase-js";
import { Resend } from "resend";

const resend = process.env.RESEND_API_KEY ? new Resend(process.env.RESEND_API_KEY) : null;

// Validation Regex for secure password
// 8+ chars, number, symbol, upper, lower
const PASSWORD_REGEX = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&._\-\/,#])[A-Za-z\d@$!%*?&._\-\/,#]{8,}$/;

/**
 * Initiates the registration process.
 * Verifies username uniqueness and sends a 6-digit code.
 */
export async function initiateMoveRegistration(formData: any) {
  const { email, username, password } = formData;
  const supabase = await createClient();

  // 1. Validate password
  if (!PASSWORD_REGEX.test(password)) {
    return { 
      success: false, 
      error: "La contrasenya ha de tenir 8+ caràcters, una majúscula, una minúscula, un número i un símbol." 
    };
  }

  // 2. Check username uniqueness in move_profiles
  const { data: existingUser } = await supabase
    .from("move_profiles")
    .select("username")
    .eq("username", username)
    .maybeSingle();

  if (existingUser) {
    return { success: false, error: "Aquest nom d'usuari ja està agafat." };
  }

  // 3. Generate 6-digit code
  const code = Math.floor(100000 + Math.random() * 900000).toString();

  // 4. Store in move_temp_registrations
  const expiresAt = new Date();
  expiresAt.setMinutes(expiresAt.getMinutes() + 15); // 15 min expiry

  const { error: dbError } = await supabase
    .from("move_temp_registrations")
    .upsert({
      email,
      username,
      verification_code: code,
      payload: formData,
      expires_at: expiresAt.toISOString()
    }, { onConflict: 'email' });

  if (dbError) {
    console.error("DB Error:", dbError);
    return { success: false, error: "Error en el registre temporal." };
  }

  // 5. Send Email via Resend
  if (resend) {
    try {
      await resend.emails.send({
        from: "Move Activity Hub <onboarding@resend.dev>",
        to: [email],
        subject: "Codi de verificació - Move",
        html: `
          <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #eee; rounded: 20px;">
            <h2 style="color: #843aea; text-align: center;">Verifica el teu compte Move</h2>
            <p>Hola!</p>
            <p>Estàs a un pas d'unir-te a la comunitat d'activitats Move. Utilitza el següent codi per verificar el teu correu:</p>
            <div style="background: #f4f4f4; padding: 20px; text-align: center; font-size: 32px; font-weight: bold; letter-spacing: 5px; color: #111; margin: 30px 0;">
              ${code}
            </div>
            <p style="font-size: 12px; color: #666; margin-top: 40px; border-top: 1px solid #eee; padding-top: 20px;">
              Aquest és un missatge automàtic, si us plau <strong>no respongueu</strong> a aquest correu. Si no has demanat aquest codi, pots ignorar aquest missatge.
            </p>
          </div>
        `
      });
    } catch (emailErr) {
      console.error("Email Error:", emailErr);
      return { success: false, error: "Error en enviar el correu de verificació." };
    }
  } else {
    console.warn("RESEND_API_KEY no configurada. Codi:", code);
    // In dev mode without key, we might want to return success for testing, 
    // but for production it should be an error.
  }

  return { success: true };
}

/**
 * Verifies the 6-digit code and creates the actual user.
 */
export async function verifyAndCompleteSignUp(email: string, code: string) {
  const supabase = await createClient();

  // 1. Check code in temp table
  const { data: temp, error: fetchError } = await supabase
    .from("move_temp_registrations")
    .select("*")
    .eq("email", email)
    .maybeSingle();

  if (fetchError || !temp) {
    return { success: false, error: "No s'ha trobat cap registre pendent." };
  }

  if (temp.verification_code !== code) {
    return { success: false, error: "El codi de verificació no és vàlid." };
  }

  if (new Date(temp.expires_at) < new Date()) {
    return { success: false, error: "El codi ha caducat. Torna a intentar el registre." };
  }

  // 2. Create actual Supabase Auth user
  // We use signUp here. If email confirmation is enabled in dashboard, 
  // it would send another email, so it's best to have it disabled or managed differently.
  const { data: authData, error: authError } = await supabase.auth.signUp({
    email: temp.email,
    password: temp.payload.password,
    options: {
      data: {
        username: temp.username,
        full_name: temp.payload.name,
      }
    }
  });

  if (authError) {
    return { success: false, error: authError.message };
  }

  if (!authData.user) {
    return { success: false, error: "Error en crear l'usuari." };
  }

  // 3. Create Profile
  const { error: profileError } = await supabase
    .from("move_profiles")
    .insert([{
      id: authData.user.id,
      username: temp.username,
      full_name: temp.payload.name,
      surname: temp.payload.surname,
      phone: temp.payload.phone,
      location: temp.payload.location
    }]);

  if (profileError) {
    console.error("Profile Error:", profileError);
    return { success: false, error: "Usuari creat però ha fallat la creació del perfil." };
  }

  // 4. Cleanup temp registration
  await supabase.from("move_temp_registrations").delete().eq("email", email);

  return { success: true };
}

/**
 * Simple Login
 */
export async function loginMoveUser(formData: any) {
  const { email, password } = formData;
  const supabase = await createClient();

  const { data, error } = await supabase.auth.signInWithPassword({
    email,
    password
  });

  if (error) {
    return { success: false, error: "Correu o contrasenya incorrectes." };
  }

  return { success: true, user: data.user };
}

/**
 * Logout
 */
export async function logoutMoveUser() {
  const supabase = await createClient();
  await supabase.auth.signOut();
  return { success: true };
}

"use server";

import { createClient } from "@/lib/supabase/server";

/**
 * Join an activity
 */
export async function joinMoveActivity(activityId: string) {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) {
    return { success: false, error: "Has d'haver iniciat sessió." };
  }

  // Check if profile exists
  const { data: profile } = await supabase
    .from("move_profiles")
    .select("id")
    .eq("id", session.user.id)
    .maybeSingle();

  if (!profile) {
    return { success: false, error: "Perfil d'usuari Move no trobat." };
  }

  const { error } = await supabase
    .from("move_activity_participants")
    .insert([{
      activity_id: activityId,
      profile_id: profile.id
    }]);

  if (error) {
    if (error.code === '23505') {
      return { success: false, error: "Ja estàs apuntat a aquesta activitat." };
    }
    return { success: false, error: "Error en apuntar-se a l'activitat." };
  }

  return { success: true };
}

/**
 * Leave an activity
 */
export async function leaveMoveActivity(activityId: string) {
  const supabase = await createClient();
  const { data: { session } } = await supabase.auth.getSession();

  if (!session) {
    return { success: false, error: "Has d'haver iniciat sessió." };
  }

  const { error } = await supabase
    .from("move_activity_participants")
    .delete()
    .eq("activity_id", activityId)
    .eq("profile_id", session.user.id);

  if (error) {
    return { success: false, error: "Error en desapuntar-se de l'activitat." };
  }

  return { success: true };
}

/**
 * Get participants of an activity (nicks only)
 */
export async function getActivityParticipants(activityId: string) {
  const supabase = await createClient();

  const { data, error } = await supabase
    .from("move_activity_participants")
    .select(`
      profile:move_profiles (
        username
      )
    `)
    .eq("activity_id", activityId);

  if (error) {
    console.error("Error fetching participants:", error);
    return [];
  }

  return data.map((d: any) => d.profile.username);
}

