import { createClient } from "@/lib/supabase/client";
import { Plus, Trash2, Save, Loader2 } from "lucide-react";

type CvItem = { title?: string; place?: string; subtitle?: string; date?: string; date_start?: string; date_end?: string; description?: string; name?: string; level?: string; items?: string[] };

const SECTIONS = [
  { type: "experiencia", label: "Experiència Professional" },
  { type: "educacion", label: "Formació Acadèmica" },
  { type: "idiomas", label: "Idiomes" },
  { type: "habilidades", label: "Eines i Software" },
];

function normalizeContent(raw: any): CvItem[] {
  if (!raw) return [];
  // If array directly (seed format)
  if (Array.isArray(raw)) return raw;
  // If object with language keys {ca:[...], es:[...]}
  const localized = raw.ca || raw.es || raw.en || [];
  return Array.isArray(localized) ? localized : [];
}

export default function AdminCV() {
  const supabase = createClient();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);
  const [sections, setSections] = useState<Record<string, { id: string | null; items: CvItem[] }>>({
    experiencia: { id: null, items: [] },
    educacion: { id: null, items: [] },
    idiomas: { id: null, items: [] },
    habilidades: { id: null, items: [] },
  });

  const fetchData = async () => {
    setLoading(true);
    const { data } = await supabase.from("cv_sections").select("*").order("sort_order", { ascending: true });
    if (data) {
      const newSections = { ...sections };
      for (const row of data) {
        if (newSections[row.type] !== undefined) {
          newSections[row.type] = { id: row.id, items: normalizeContent(row.content) };
        }
      }
      setSections(newSections);
    }
    setLoading(false);
  };

  useEffect(() => { fetchData(); }, []);

  const handleSave = async (type: string) => {
    const sec = sections[type];
    setSaving(type);
    const payload = { type, content: sec.items };
    if (sec.id) {
      await supabase.from("cv_sections").update(payload).eq("id", sec.id);
    } else {
      const { data } = await supabase.from("cv_sections").insert([payload]).select().single();
      if (data) setSections(prev => ({ ...prev, [type]: { ...prev[type], id: data.id } }));
    }
    setSaving(null);
  };

  const updateSection = (type: string, items: CvItem[]) => {
    setSections(prev => ({ ...prev, [type]: { ...prev[type], items } }));
  };

  const addItem = (type: string) => {
    const blank: CvItem = type === "idiomas"
      ? { name: "", level: "" }
      : type === "habilidades"
      ? { name: "", level: "" }
      : { title: "", place: "", date_start: "", date_end: "", description: "" };
    updateSection(type, [...sections[type].items, blank]);
  };

  const removeItem = (type: string, idx: number) => {
    updateSection(type, sections[type].items.filter((_, i) => i !== idx));
  };

  const updateItem = (type: string, idx: number, field: string, value: string) => {
    const items = [...sections[type].items];
    items[idx] = { ...items[idx], [field]: value };
    updateSection(type, items);
  };

  if (loading) return <div className="p-4 md:p-8 text-[var(--color-muted)] animate-pulse">Carregant seccions del CV...</div>;

  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500 w-full">
      <div className="mb-8 border-b border-[var(--color-border)] pb-5">
        <h1 className="text-3xl font-black text-[var(--color-text)] tracking-tight">Constructor de CV</h1>
        <p className="text-[var(--color-muted)] text-sm mt-1">Edita i desa cada secció independentment.</p>
      </div>

      <div className="space-y-8">
        {SECTIONS.map(({ type, label }) => {
          const sec = sections[type];
          const isLang = type === "idiomas";
          const isSkill = type === "habilidades";
          const isSaving = saving === type;

          return (
            <div key={type} className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-2xl overflow-hidden">
              {/* Section Header */}
              <div className="flex justify-between items-center px-6 py-4 border-b border-[var(--color-border)] bg-[var(--color-surface-2)]">
                <div>
                  <h2 className="font-bold text-[var(--color-text)]">{label}</h2>
                  <p className="text-xs text-[var(--color-muted)] mt-0.5">{sec.items.length} entrades</p>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => addItem(type)}
                    className="flex items-center gap-2 px-3 py-2 rounded-xl text-sm font-semibold transition-all text-[var(--color-muted)] hover:text-[var(--color-accent)] border border-[var(--color-border)] hover:border-[var(--color-accent)]"
                  >
                    <Plus className="w-4 h-4" /> Afegir
                  </button>
                  <button
                    onClick={() => handleSave(type)}
                    disabled={isSaving}
                    className="flex items-center gap-2 px-4 py-2 rounded-xl text-sm font-semibold text-white transition-all"
                    style={{ background: "var(--color-accent)" }}
                  >
                    {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
                    Desar
                  </button>
                </div>
              </div>

              {/* Items */}
              <div className="divide-y divide-[var(--color-border)]">
                {sec.items.length === 0 && (
                  <p className="text-[var(--color-muted)] text-sm text-center py-8">
                    Cap entrada. Fes clic a "Afegir" per crear-ne una.
                  </p>
                )}
                {sec.items.map((item, idx) => (
                  <div key={idx} className="flex gap-4 items-start px-6 py-4 hover:bg-[var(--color-surface-2)] transition-colors group">
                    <div className="flex-1 grid gap-2">
                      {(isLang || isSkill) ? (
                        <div className="grid grid-cols-2 gap-2">
                          <input
                            value={item.name ?? ""}
                            onChange={e => updateItem(type, idx, "name", e.target.value)}
                            placeholder="Nom (ex: English)"
                            className="bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors"
                          />
                          <input
                            value={item.level ?? ""}
                            onChange={e => updateItem(type, idx, "level", e.target.value)}
                            placeholder="Nivell (ex: Natiu / Expert)"
                            className="bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors"
                          />
                        </div>
                      ) : (
                        <>
                          <div className="grid grid-cols-3 gap-2">
                            <input
                              value={item.title ?? ""}
                              onChange={e => updateItem(type, idx, "title", e.target.value)}
                              placeholder="Títol del càrrec / estudis"
                              className="col-span-2 bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors"
                            />
                            <input
                              value={item.date_start ?? ""}
                              onChange={e => updateItem(type, idx, "date_start", e.target.value)}
                              placeholder="Inici (ex: 2021)"
                              className="bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors font-mono"
                            />
                          </div>
                          <div className="grid grid-cols-3 gap-2">
                            <input
                              value={item.place ?? item.subtitle ?? ""}
                              onChange={e => updateItem(type, idx, "place", e.target.value)}
                              placeholder="Empresa / Centre"
                              className="col-span-2 bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors"
                            />
                            <input
                              value={item.date_end ?? ""}
                              onChange={e => updateItem(type, idx, "date_end", e.target.value)}
                              placeholder="Fi (o buit = Actual)"
                              className="bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-text)] focus:border-[var(--color-accent)] outline-none transition-colors font-mono"
                            />
                          </div>
                          <textarea
                            value={item.description ?? ""}
                            onChange={e => updateItem(type, idx, "description", e.target.value)}
                            placeholder="Descripció breu..."
                            rows={2}
                            className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-xl px-3 py-2 text-sm text-[var(--color-muted)] focus:border-[var(--color-accent)] outline-none transition-colors resize-none"
                          />
                        </>
                      )}
                    </div>
                    <button
                      onClick={() => removeItem(type, idx)}
                      className="mt-1 p-2 rounded-lg text-[var(--color-muted)] hover:text-red-500 hover:bg-red-500/10 transition-all opacity-0 group-hover:opacity-100"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import Link from "next/link";
import { Eye, Users, Briefcase, Clock, TrendingUp, ArrowRight } from "lucide-react";
import { ActivityChart } from "@/components/admin/ActivityChart";

export default async function AdminDashboard() {
  const supabase = await createClient();

  // 30 days ago calculation
  const thirtyDaysAgo = new Date();
  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  const thirtyDaysStr = thirtyDaysAgo.toISOString();

  // Fetch all data in parallel
  const [
    { count: totalEvents },
    { count: totalWorks },
    { count: totalCompanies },
    { count: totalTokens },
    { data: recentEvents },
    { data: topWorks },
    { data: last30DaysActivity },
  ] = await Promise.all([
    supabase.from("analytics_events").select("*", { count: "exact", head: true }),
    supabase.from("works").select("*", { count: "exact", head: true }),
    supabase.from("companies").select("*", { count: "exact", head: true }),
    supabase.from("access_tokens").select("*", { count: "exact", head: true }),
    supabase
      .from("analytics_events")
      .select("id, event_type, duration_sec, scroll_pct, created_at, access_tokens(token, companies(name))")
      .order("created_at", { ascending: false })
      .limit(8),
    supabase
      .from("analytics_events")
      .select("work_id, works(title)")
      .not("work_id", "is", null)
      .limit(100),
    supabase
      .from("analytics_events")
      .select("created_at")
      .gte("created_at", thirtyDaysStr),
  ]);

  // Generate 30 days chart data
  const activityMap = new Map<string, number>();

  // Initialize last 30 days with 0
  for (let i = 29; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    const key = d.toLocaleDateString("ca-ES", { day: "2-digit", month: "short" });
    activityMap.set(key, 0);
  }

  // Populate data
  (last30DaysActivity || []).forEach((event) => {
    const d = new Date(event.created_at);
    const key = d.toLocaleDateString("ca-ES", { day: "2-digit", month: "short" });
    if (activityMap.has(key)) {
      activityMap.set(key, activityMap.get(key)! + 1);
    }
  });

  const chartData = Array.from(activityMap.entries()).map(([date, count]) => ({ date, count }));

  // Aggregate work views
  const workViewCounts: Record<string, { title: string; count: number }> = {};
  (topWorks ?? []).forEach((e: any) => {
    if (!e.work_id) return;
    const title = e.works?.title ?? e.work_id;
    if (!workViewCounts[e.work_id]) workViewCounts[e.work_id] = { title, count: 0 };
    workViewCounts[e.work_id].count++;
  });
  const sortedWorks = Object.entries(workViewCounts)
    .sort(([, a], [, b]) => b.count - a.count)
    .slice(0, 5);

  // Average read duration
  const avgDuration = recentEvents?.length
    ? Math.round(
        (recentEvents.reduce((sum: number, e: any) => sum + (e.duration_sec ?? 0), 0) /
          recentEvents.length) as number
      )
    : 0;

  const stats = [
    { label: "Pàgines Vistes", value: totalEvents ?? 0, icon: Eye, accent: false },
    { label: "Enllaços d'Accés", value: totalTokens ?? 0, icon: Users, accent: false },
    { label: "Treballs Publicats", value: totalWorks ?? 0, icon: Briefcase, accent: false },
    { label: "Empreses", value: totalCompanies ?? 0, icon: TrendingUp, accent: true },
  ];

  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500 w-full mx-auto">
      {/* Header */}
      <div className="mb-10 border-b border-[var(--color-border)] pb-6">
        <h1 className="text-3xl font-bold text-[var(--color-text)] mb-2 tracking-tight">Panel de Control</h1>
        <p className="text-[var(--color-muted)]">Vista general de l&apos;activitat i rendiment del portfolio.</p>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        {stats.map((stat) => (
          <div
            key={stat.label}
            className={`bg-[var(--color-surface)] border rounded-2xl p-6 flex flex-col gap-3 transition-all hover:scale-[1.02] ${
              stat.accent ? "border-[var(--color-accent)] shadow-lg shadow-[var(--color-accent)]/10" : "border-[var(--color-border)]"
            }`}
          >
            <div className={`w-9 h-9 rounded-xl flex items-center justify-center ${stat.accent ? "bg-[var(--color-accent)]/15 text-[var(--color-accent)]" : "bg-[var(--color-bg)] text-[var(--color-muted)]"}`}>
              <stat.icon className="w-5 h-5" />
            </div>
            <div>
              <p className="text-3xl font-black text-[var(--color-text)] tracking-tight">{stat.value}</p>
              <p className="text-xs text-[var(--color-muted)] uppercase tracking-widest font-bold mt-1">{stat.label}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Activity Chart */}
      <div className="mb-8 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-2xl p-6 shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h2 className="font-bold text-[var(--color-text)] text-lg">Visites Últims 30 Dies</h2>
        </div>
        <ActivityChart data={chartData} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Recent Activity */}
        <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-2xl p-6 shadow-sm">
          <div className="flex justify-between items-center mb-5">
            <h2 className="font-bold text-[var(--color-text)] text-lg">Activitat Recent</h2>
            <div className="flex items-center gap-2 text-xs text-[var(--color-muted)]">
              <Clock className="w-3.5 h-3.5" />
              Temps mitjà: <span className="font-bold text-[var(--color-text)]">{avgDuration}s</span>
            </div>
          </div>
          {!recentEvents?.length ? (
            <p className="text-[var(--color-muted)] text-sm text-center py-8">Encara no hi ha visites registrades.</p>
          ) : (
            <div className="space-y-3">
              {recentEvents.map((ev: any) => {
                const company = ev.access_tokens?.companies?.name ?? "Visitant Directe";
                const date = new Date(ev.created_at).toLocaleDateString("ca-ES", { day: "2-digit", month: "short" });
                const time = new Date(ev.created_at).toLocaleTimeString("ca-ES", { hour: "2-digit", minute: "2-digit" });
                return (
                  <div key={ev.id} className="flex items-center justify-between py-2.5 border-b border-[var(--color-border)] last:border-0">
                    <div className="flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-[var(--color-accent)]/10 flex items-center justify-center text-xs font-bold text-[var(--color-accent)]">
                        {company.charAt(0).toUpperCase()}
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-[var(--color-text)] truncate max-w-[150px] sm:max-w-xs">{company}</p>
                        <p className="text-[10px] uppercase font-bold tracking-wider text-[var(--color-muted)] mt-0.5">{ev.event_type === "page_view" ? "Vista general" : "Lectura projecte"}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-xs text-[var(--color-muted)]">{date} · {time}</p>
                      {ev.duration_sec != null && (
                        <p className="text-xs font-medium text-[var(--color-accent)] mt-0.5">{ev.duration_sec}s · {ev.scroll_pct ?? 0}% scroll</p>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* Top Works */}
        <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-2xl p-6 shadow-sm">
          <div className="flex justify-between items-center mb-5">
            <h2 className="font-bold text-[var(--color-text)] text-lg">Projectes Més Vistos</h2>
            <Link href="/admin/trabajos" className="text-xs font-bold text-[var(--color-accent)] hover:text-[var(--color-accent-hover)] flex items-center gap-1 transition-colors uppercase tracking-wider">
              Veure tots <ArrowRight className="w-3 h-3" />
            </Link>
          </div>
          {!sortedWorks.length ? (
            <p className="text-[var(--color-muted)] text-sm text-center py-8">Encara no hi ha dades específiques de projectes.</p>
          ) : (
            <div className="space-y-4">
              {sortedWorks.map(([id, { title, count }], i) => {
                const max = sortedWorks[0][1].count;
                const pct = Math.round((count / max) * 100);
                return (
                  <div key={id}>
                    <div className="flex justify-between items-baseline mb-2">
                      <span className="text-sm font-semibold text-[var(--color-text)] truncate pr-4">{title}</span>
                      <span className="text-[11px] font-bold text-[var(--color-muted)] shrink-0 bg-[var(--color-bg)] border border-[var(--color-border)] px-2 py-0.5 rounded-full">{count} vista{count !== 1 ? "s" : ""}</span>
                    </div>
                    <div className="w-full bg-[var(--color-bg)] rounded-full h-2 border border-[var(--color-border)]/50">
                      <div
                        className="h-full rounded-full bg-gradient-to-r from-[var(--color-accent)]/50 to-[var(--color-accent)] transition-all duration-1000"
                        style={{ width: `${pct}%` }}
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Plus, Edit2, Trash2, X, ChevronDown, ChevronRight, GripVertical, Building2, Landmark, ArrowUp, ArrowDown, Sparkles } from "lucide-react";

export default function AdminEmpresas() {
  const [empresas, setEmpresas] = useState<any[]>([]);
  const [orderedEmpresas, setOrderedEmpresas] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingCompany, setEditingCompany] = useState<any>(null);
  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    sector: "",
    location: "",
    website: "",
    start_date: "",
    end_date: "",
    logo_url: "",
    description: "",
    is_freelance: false,
    parent_id: null as string | null,
  });
  const [sortBy, setSortBy] = useState<"date" | "name" | "custom">("custom");

  const supabase = createClient();

  const fetchEmpresas = async () => {
    setLoading(true);
    let query = supabase.from("companies").select("*");

    if (sortBy === "name") {
      query = query.order("name", { ascending: true });
    } else if (sortBy === "date") {
      query = query.order("start_date", { ascending: false });
    }

    const { data } = await query;
    if (data) {
      setEmpresas(data);
      if (sortBy === "custom") {
        buildHierarchy(data);
      } else {
        setOrderedEmpresas(data);
      }
    }
    setLoading(false);
  };

  const buildHierarchy = (flatData: any[]) => {
    // We sort parents by name or date, but keep children under them
    const parents = flatData.filter(e => !e.parent_id).sort((a,b) => a.name.localeCompare(b.name));
    const children = flatData.filter(e => e.parent_id);

    const result: any[] = [];

    parents.forEach(parent => {
      result.push({ ...parent, depth: 0 });
      const myChildren = children.filter(c => c.parent_id === parent.id).sort((a,b) => a.name.localeCompare(b.name));
      myChildren.forEach(child => {
        result.push({ ...child, depth: 1 });
        const grandChildren = children.filter(gc => gc.parent_id === child.id).sort((a,b) => a.name.localeCompare(b.name));
        grandChildren.forEach(gc => {
          result.push({ ...gc, depth: 2 });
        });
      });
    });

    const activeIds = new Set(result.map(r => r.id));
    const orphans = flatData.filter(e => !activeIds.has(e.id));
    setOrderedEmpresas([...result, ...orphans]);
  };

  useEffect(() => {
    fetchEmpresas();
  }, [sortBy]);

  // Reordering Logic
  const moveItem = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...orderedEmpresas];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;

    if (targetIndex < 0 || targetIndex >= newOrder.length) return;

    const temp = newOrder[index];
    newOrder[index] = newOrder[targetIndex];
    newOrder[targetIndex] = temp;

    setOrderedEmpresas(newOrder);
    setSortBy("custom");
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (!confirm("¿Segur que vols eliminar aquesta empresa? Tots els seus treballs també podrien veure's afectats.")) return;
    await supabase.from("companies").delete().eq("id", id);
    fetchEmpresas();
  };

  const handleNew = () => {
    setEditingCompany(null);
    setFormData({
      name: "",
      slug: "",
      sector: "",
      location: "",
      website: "",
      start_date: "",
      end_date: "",
      logo_url: "",
      description: "",
      is_freelance: false,
      parent_id: null,
    });
    setIsModalOpen(true);
  };

  const handleEdit = (emp: any) => {
    setEditingCompany(emp);
    setFormData({
      name: emp.name || "",
      slug: emp.slug || "",
      sector: emp.sector || "",
      location: emp.location || "",
      website: emp.website || "",
      start_date: emp.start_date || "",
      end_date: emp.end_date || "",
      logo_url: emp.logo_url || "",
      description: emp.description || "",
      is_freelance: emp.is_freelance || false,
      parent_id: emp.parent_id || null,
    });
    setIsModalOpen(true);
  };

  const handleNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newName = e.target.value;
    setFormData(prev => {
      const currentSlug = prev.slug;
      const targetSlug = prev.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '');
      const autoSlug = newName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)+/g, '');
      const newSlug = (currentSlug === '' || currentSlug === targetSlug) ? autoSlug : currentSlug;
      return { ...prev, name: newName, slug: newSlug };
    });
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
