"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";
import { Plus, Edit2, Trash2, Copy, Lock, Star, Eye } from "lucide-react";
import { useRouter } from "next/navigation";

export default function AdminTrabajos() {
  const [works, setWorks] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState("all");
  const [companyFilter, setCompanyFilter] = useState("all");
  const supabase = createClient();
  const router = useRouter();

  const fetchWorks = async () => {
    setLoading(true);
    const { data } = await supabase
      .from("works")
      .select("*, companies(name)")
      .order("created_at", { ascending: false });
    if (data) setWorks(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchWorks();
  }, []);

  const handleDelete = async (id: string, title: string) => {
    if (!confirm(`¿Estás seguro de que quieres eliminar el trabajo "${title}" permanentemente?`)) return;
    await supabase.from("works").delete().eq("id", id);
    fetchWorks();
  };

  const handleDuplicate = async (work: any) => {
    if (!confirm(`¿Duplicar el trabajo "${work.title}"?`)) return;

    const newWork = {
      ...work,
      id: undefined,
      created_at: undefined,
      updated_at: undefined,
      companies: undefined,
      slug: `${work.slug}-copia-${Date.now()}`,
      title: `${work.title} (Copia)`,
      status: 'draft'
    };

    Object.keys(newWork).forEach(key => newWork[key] === undefined && delete newWork[key]);

    const { error } = await supabase.from("works").insert([newWork]);
    if (error) {
      alert("Error duplicando: " + error.message);
    } else {
      fetchWorks();
    }
  };

  const filteredWorks = works.filter((wk) => {
    if (statusFilter !== "all" && wk.status !== statusFilter) return false;
    if (companyFilter !== "all" && (wk.company_id || "none") !== companyFilter) return false;
    return true;
  });

  const uniqueCompanies = Array.from(new Set(works.map(w => w.company_id || "none")));

  return (
    <div className="p-4 md:p-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center mb-8 border-b border-[var(--color-border)] pb-4">
        <h1 className="text-3xl font-display font-bold text-[var(--color-text)]">Llistat de Projectes i Treballs</h1>
        <button onClick={() => router.push("/admin/trabajos/nuevo/editar")} className="bg-[var(--color-accent)] hover:bg-[var(--color-accent-hover)] text-white px-5 py-2.5 rounded-lg flex items-center justify-center transition-colors font-bold shadow-lg shadow-[var(--color-accent-glow)]">
          <Plus className="w-5 h-5 mr-2" /> Nou Treball
        </button>
      </div>

      <div className="flex flex-col sm:flex-row gap-4 mb-6">
        <select 
          value={statusFilter} 
          onChange={(e) => setStatusFilter(e.target.value)}
          className="bg-[var(--color-surface)] border border-[var(--color-border)] text-[var(--color-text)] px-4 py-2 rounded-lg focus:outline-none focus:border-[var(--color-accent)] text-sm font-medium"
        >
          <option value="all">Tots els estats</option>
          <option value="published">Publicats</option>
          <option value="draft">Esborranys</option>
          <option value="archived">Arxivats</option>
        </select>

        <select 
          value={companyFilter} 
          onChange={(e) => setCompanyFilter(e.target.value)}
          className="bg-[var(--color-surface)] border border-[var(--color-border)] text-[var(--color-text)] px-4 py-2 rounded-lg focus:outline-none focus:border-[var(--color-accent)] text-sm font-medium"
        >
          <option value="all">Totes les empreses</option>
          {uniqueCompanies.map((id) => {
            const name = id === "none" ? "Sense associar" : works.find(w => w.company_id === id)?.companies?.name || "Desconeguda";
            return <option key={id} value={id}>{name}</option>;
          })}
        </select>
      </div>

      <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl shadow-2xl overflow-hidden">
         {loading ? (
           <div className="p-12 text-center text-[var(--color-muted)]">Carregant treballs...</div>
         ) : filteredWorks.length === 0 ? (
           <div className="p-12 text-center text-[var(--color-muted)] flex flex-col items-center">
             <div className="w-16 h-16 bg-[var(--color-bg)] rounded-full flex items-center justify-center mb-4 border border-[var(--color-border)]">
               <svg className="w-8 h-8 text-[var(--color-border)]" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 002-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" /></svg>
             </div>
             No hi ha treballs que coincideixin amb els filtres.
           </div>
         ) : (
           <div className="overflow-x-auto">
             <table className="w-full text-left text-sm min-w-[600px]">
               <thead className="bg-[var(--color-bg)] text-[var(--color-muted)] border-b border-[var(--color-border)]">
                 <tr>
                   <th className="px-6 py-4 font-black uppercase tracking-widest text-[10px]">Títol i Empresa</th>
                   <th className="px-6 py-4 font-black uppercase tracking-widest text-[10px]">Estat</th>
                   <th className="px-6 py-4 font-black uppercase tracking-widest text-[10px] hidden sm:table-cell">Visibilitat</th>
                   <th className="px-6 py-4 font-black uppercase tracking-widest text-[10px] text-right">Accions</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-[var(--color-border)]">
                  {filteredWorks.map((wk) => (
                    <tr key={wk.id} className="hover:bg-[var(--color-surface-2)] transition-colors group">
                      <td className="px-6 py-4">
                        <p className="font-bold text-[var(--color-text)] mb-0.5">{wk.title}</p>
                        <p className="text-[var(--color-muted)] text-xs font-medium">{wk.companies?.name || "Sense associar"}</p>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2.5 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${
                          wk.status === 'published' 
                           ? 'bg-green-500/10 text-green-600 dark:text-green-400 border-green-500/20' 
                           : wk.status === 'archived' 
                           ? 'bg-gray-500/10 text-gray-600 dark:text-gray-400 border-gray-500/20' 
                           : 'bg-yellow-500/10 text-yellow-700 dark:text-yellow-400 border-yellow-500/20'
                        }`}>
                          {wk.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 hidden sm:table-cell">
                         <div className="flex gap-2">
                           {wk.featured && <span title="Destacat"><Star className="w-4 h-4 text-[var(--color-accent)] fill-[var(--color-accent)]" /></span>}
                           {wk.protected && <span title="Protegit amb PIN"><Lock className="w-4 h-4 text-[var(--color-muted)]" /></span>}
                         </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2 sm:gap-4">
                          <button className="text-[var(--color-accent)] hover:text-[var(--color-accent-hover)] transition-colors opacity-70 sm:opacity-50 group-hover:opacity-100 p-1" title="Vista Prèvia">
                            <Eye className="w-4 h-4" />
                          </button>
                          <button onClick={() => handleDuplicate(wk)} className="text-[var(--color-muted)] hover:text-blue-500 transition-colors opacity-70 sm:opacity-50 group-hover:opacity-100 p-1" title="Duplicar">
                            <Copy className="w-4 h-4" />
                          </button>
                          <button onClick={() => router.push(`/admin/trabajos/${wk.id}/editar`)} className="text-[var(--color-muted)] hover:text-[var(--color-accent)] transition-colors opacity-70 sm:opacity-50 group-hover:opacity-100 p-1" title="Editar">
                            <Edit2 className="w-4 h-4" />
                          </button>
                          <button onClick={() => handleDelete(wk.id, wk.title)} className="text-[var(--color-muted)] hover:text-red-500 transition-colors opacity-70 sm:opacity-50 group-hover:opacity-100 p-1" title="Eliminar">
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
               </tbody>
             </table>
           </div>
         )}
      </div>
    </div>
  );
}

import React from "react";
import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { renderToStream, Document, Page, Text, View, StyleSheet, Font } from "@react-pdf/renderer";

Font.register({
  family: 'Montserrat',
  fonts: [
    { src: 'https://fonts.gstatic.com/s/montserrat/v26/JTUSjIg1_i6t8kCHKm459Wlhzg.ttf', fontWeight: 400 },
    { src: 'https://fonts.gstatic.com/s/montserrat/v26/JTURjIg1_i6t8kCHKm45_dJE3gnD_g.ttf', fontWeight: 700 },
  ]
});

const styles = StyleSheet.create({
  page: { padding: 40, fontFamily: 'Montserrat', backgroundColor: '#ffffff' },
  header: { borderBottomWidth: 2, borderBottomColor: '#FF0A0A', paddingBottom: 15, marginBottom: 20 },
  name: { fontSize: 26, fontWeight: 700, color: '#111' },
  tagline: { fontSize: 11, color: '#555', marginTop: 5, fontWeight: 400 },
  contact: { flexDirection: 'row', gap: 15, marginTop: 10, fontSize: 9, color: '#777' },
  contactItem: { flexDirection: 'row', alignItems: 'center' },
  section: { marginBottom: 18 },
  sectionTitle: { fontSize: 10, fontWeight: 700, textTransform: 'uppercase', color: '#FF0A0A', borderBottomWidth: 1, borderBottomColor: '#eee', paddingBottom: 4, marginBottom: 10 },
  item: { marginBottom: 12 },
  itemHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start' },
  itemTitleBlock: { flex: 1, paddingRight: 10 },
  itemTitle: { fontSize: 12, fontWeight: 700, color: '#111' },
  itemSubtitle: { fontSize: 10, fontWeight: 700, color: '#FF0A0A', marginTop: 2 },
  itemDate: { fontSize: 9, color: '#888' },
  itemDesc: { fontSize: 9, color: '#444', marginTop: 4, lineHeight: 1.5, fontWeight: 400 },
  langGrid: { flexDirection: 'row', flexWrap: 'wrap', gap: 10 },
  langItem: { width: '30%', backgroundColor: '#f8f8f8', padding: 8, borderRadius: 4 },
  langName: { fontSize: 10, fontWeight: 700 },
  langLevel: { fontSize: 8, color: '#888', marginTop: 2 }
});

const CVDocument = ({ aboutData, experience, education, languages }: any) => {
  return (
    <Document>
      <Page size="A4" style={styles.page}>
        <View style={styles.header}>
          <Text style={styles.name}>{aboutData?.name ?? "Marc"}</Text>
          <Text style={styles.tagline}>{typeof aboutData?.tagline === 'object' ? aboutData.tagline.ca : (aboutData?.tagline ?? "")}</Text>
          <View style={styles.contact}>
            {aboutData?.email && <Text style={styles.contactItem}>✉  {aboutData.email}</Text>}
            {aboutData?.phone && <Text style={styles.contactItem}>📞  {aboutData.phone}</Text>}
          </View>
        </View>

        {experience && experience.length > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Experiència professional</Text>
            {experience.map((item: any, i: number) => {
              const content = Array.isArray(item.content) ? item.content : [];
              return content.map((exp: any, j: number) => (
                <View key={`exp-${i}-${j}`} style={styles.item}>
                  <View style={styles.itemHeader}>
                    <View style={styles.itemTitleBlock}>
                      <Text style={styles.itemTitle}>{exp.title ?? ""}</Text>
                      <Text style={styles.itemSubtitle}>{exp.place ?? exp.company ?? ""}</Text>
                    </View>
                    <Text style={styles.itemDate}>
                      {exp.date_start ?? ""}{exp.date_end ? " – " + exp.date_end : " – Actual"}
                    </Text>
                  </View>
                  {exp.description && <Text style={styles.itemDesc}>{exp.description}</Text>}
                </View>
              ));
            })}
          </View>
        )}

        {education && education.length > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Formació</Text>
            {education.map((item: any, i: number) => {
              const content = Array.isArray(item.content) ? item.content : [];
              return content.map((edu: any, j: number) => (
                <View key={`edu-${i}-${j}`} style={styles.item}>
                  <View style={styles.itemHeader}>
                    <View style={styles.itemTitleBlock}>
                      <Text style={styles.itemTitle}>{edu.title ?? ""}</Text>
                      <Text style={styles.itemSubtitle}>{edu.place ?? edu.institution ?? ""}</Text>
                    </View>
                    <Text style={styles.itemDate}>
                      {edu.date_start ?? ""}{edu.date_end ? " – " + edu.date_end : ""}
                    </Text>
                  </View>
                  {edu.description && <Text style={styles.itemDesc}>{edu.description}</Text>}
                </View>
              ));
            })}
          </View>
        )}

        {languages && languages.length > 0 && (
          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Idiomes</Text>
            <View style={styles.langGrid}>
              {languages.map((item: any, i: number) => {
                const content = Array.isArray(item.content) ? item.content : [];
                return content.map((lang: any, j: number) => (
                  <View key={`lang-${i}-${j}`} style={styles.langItem}>
                    <Text style={styles.langName}>{lang.name ?? lang.title ?? ""}</Text>
                    <Text style={styles.langLevel}>{lang.level ?? ""}</Text>
                  </View>
                ));
              })}
            </View>
          </View>
        )}
      </Page>
    </Document>
  );
};

export async function GET(req: NextRequest) {
  try {
    const supabase = await createClient();

    const [cvRes, aboutRes] = await Promise.all([
      supabase.from("cv_sections").select("*").order("display_order", { ascending: true }),
      supabase.from("about_me").select("*").single()
    ]);

    const cvData = cvRes.data;
    const aboutData = aboutRes.data;

    if (!cvData) {
      return NextResponse.json({ error: "No CV data found" }, { status: 404 });
    }

    const experience = cvData.filter((s: any) => s.section === "experience");
    const education = cvData.filter((s: any) => s.section === "education");
    const languages = cvData.filter((s: any) => s.section === "languages");

    const stream = await renderToStream(
      <CVDocument 
        aboutData={aboutData} 
        experience={experience} 
        education={education} 
        languages={languages} 
      />
    );

    const chunks: Uint8Array[] = [];
    for await (const chunk of stream as any) {
      chunks.push(typeof chunk === 'string' ? Buffer.from(chunk) : chunk);
    }
    const pdfBuffer = Buffer.concat(chunks);

    return new NextResponse(pdfBuffer, {
      headers: {
        "Content-Type": "application/pdf",
        "Content-Disposition": `attachment; filename="CV-${aboutData?.name ?? 'Marc'}.pdf"`
      },
    });

  } catch (err: any) {
    console.error("PDF generation error:", err);
    return NextResponse.json({ error: "Error generating PDF: " + err.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";
import { Resend } from "resend";

// Lazy init resend only when key exists
let resend: Resend | null = null;

export async function POST(req: NextRequest) {
  try {
    const { token } = await req.json();

    if (!token) {
      return NextResponse.json({ error: "No token provided" }, { status: 400 });
    }

    const supabase = await createClient();

    // Fetch token details
    const { data: tokenData, error } = await supabase
      .from("access_tokens")
      .select("id, label, notify_email")
      .eq("token", token)
      .single();

    if (error || !tokenData) {
      return NextResponse.json({ error: "Token not found" }, { status: 404 });
    }

    if (tokenData.notify_email && process.env.RESEND_API_KEY) {
      if (!resend) resend = new Resend(process.env.RESEND_API_KEY);

      // Setup the email receiver
      const notificationEmail = process.env.NOTIFICATION_EMAIL || "marcg@example.com"; 

      await resend.emails.send({
        from: "Notificaciones Portfolio <onboarding@resend.dev>",
        to: [notificationEmail],
        subject: `Nuevo Acceso al Portfolio: ${tokenData.label}`,
        html: `<p>El usuario con el token asignado a <strong>${tokenData.label}</strong> acaba de acceder a tu portfolio.</p>`
      });

      // Update to not notify again
      await supabase
        .from("access_tokens")
        .update({ notify_email: false })
        .eq("id", tokenData.id);

      return NextResponse.json({ success: true, notified: true });
    }

    return NextResponse.json({ success: true, notified: false });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

