import { getLocale, getTranslations } from "next-intl/server";
import { PortfolioFeed } from "@/components/portfolio/PortfolioFeed";
import { PdfPresentationMode } from "@/components/portfolio/PdfPresentationMode";
import Image from "next/image";
import Link from "next/link";
import { Move, Maximize2 } from "lucide-react";

export default async function PortfolioHome({
  params,
  searchParams,
}: {
  params: Promise<{ token: string }>;
  searchParams: Promise<{ companyId?: string }>;
}) {
  const { token } = await params;
  const { companyId } = await searchParams;
  const locale = await getLocale();
  const t = await getTranslations("Index");
  const supabase = await createClient();

  let tokenData = null;
  let aboutData = null;
  let allCompanies = [];

  if (token === "preview") {
    // Only fetch common data for public view
    const [aboutRes, companiesRes] = await Promise.all([
      supabase.from("about_me").select("*").single(),
      supabase.from("companies").select("*").order("start_date", { ascending: false }),
    ]);
    aboutData = aboutRes.data;
    allCompanies = companiesRes.data || [];
  } else {
    const [tokenRes, aboutRes, companiesRes] = await Promise.all([
      supabase.from("access_tokens").select("company_ids").eq("token", token).maybeSingle(),
      supabase.from("about_me").select("*").single(),
      supabase.from("companies").select("*").order("start_date", { ascending: false }),
    ]);
    tokenData = tokenRes.data;
    aboutData = aboutRes.data;
    allCompanies = companiesRes.data || [];
  }

  const companyIdsFilter = tokenData?.company_ids || [];

  const projectClients = (allCompanies || []).filter(c => {
    if (!c.is_freelance) return false;
    if (companyIdsFilter.length === 0) return true;
    return companyIdsFilter.includes(c.id);
  });

  const collaborationCompanyIds = (allCompanies || []).filter(c => c.is_freelance).map(c => c.id);

  const { data: featuredWorks } = await supabase
    .from("works")
    .select("slug, title, cover_url, summary, tags, protected, company_id, work_date, featured, pdf_url, companies(name)")
    .eq("status", "published")
    .order("work_date", { ascending: false });

  // Filter works based on visibility and specifically ensuring that if a companyId is provided, 
  // we include those works regardless of being featured, while the client side handling 
  // will decide what to display (featured by default, or all if filtered).
  const visibleWorks = (featuredWorks || []).filter(w => {
    // 1. Check if the work belongs to a company allowed by the token
    const isAllowedByToken = companyIdsFilter.length === 0 || companyIdsFilter.includes(w.company_id);

    // 2. Check if it's a collaboration/freelance project (these are usually allowed)
    const isCollaboration = collaborationCompanyIds.includes(w.company_id);

    //Logic: Show if (Allowed by Token OR Collaboration) AND (Featured OR specific company filter)
    // Actually, in the server we should just pass all allowed works and let the client filter.
    return isAllowedByToken || isCollaboration;
  });

  const latestWorkCover = visibleWorks.length > 0 ? visibleWorks[0].cover_url : null;
  const tagline = aboutData?.tagline ? aboutData.tagline[locale] || aboutData.tagline["ca"] : "";

  return (
    <div className="min-h-screen bg-[var(--color-bg)]">

      {/* 1. BLOG-STYLE BANNER (Latest Project Background) */}
      <section className="relative w-full h-[450px] md:h-[550px] flex items-center justify-center overflow-hidden">
        {/* Background Image with Parallax-like feel */}
        {latestWorkCover ? (
          <div className="absolute inset-0 z-0">
            <Image 
              src={latestWorkCover} 
              alt="Latest Project" 
              fill 
              className="object-cover opacity-40 scale-105 blur-[2px]" 
              priority
            />
            <div className="absolute inset-0 bg-gradient-to-b from-black/60 via-[var(--color-bg)]/40 to-[var(--color-bg)]" />
          </div>
        ) : (
          <div className="absolute inset-0 bg-gradient-to-br from-[var(--color-accent)]/20 to-black/40 z-0" />
        )}

        <div className="z-10 text-center px-6 animate-in fade-in slide-in-from-bottom-12 duration-1000">
          <div className="inline-block px-4 py-1.5 rounded-full bg-[var(--color-accent)]/10 border border-[var(--color-accent)]/20 text-[var(--color-accent)] text-[10px] font-black uppercase tracking-[0.3em] mb-4 backdrop-blur-md">
            {locale === 'ca' ? 'Actualització Recent' : 'Latest Update'}
          </div>
          <div className="flex items-center justify-center gap-2 mb-8 text-[9px] text-[var(--color-muted)] font-black uppercase tracking-[0.2em] opacity-50">
            Web en procés &middot; Continguts i idiomes sota revisió (poden haver-hi faltes)
          </div>
          <h1 className="text-6xl md:text-8xl font-black text-[var(--color-text)] tracking-tighter mb-6 drop-shadow-2xl">
            {aboutData?.name || "Marc"}<span className="text-[var(--color-accent)]">.</span>
          </h1>
          <p className="text-xl md:text-2xl font-medium text-[var(--color-text)] opacity-70 max-w-2xl mx-auto drop-shadow-md leading-relaxed">
            {tagline}
          </p>

          <div className="mt-12 flex flex-wrap items-center justify-center gap-4">
             <Link
               href="?mode=present"
               className="group relative px-8 py-4 bg-white text-black font-bold rounded-2xl transition-all hover:scale-105 active:scale-95 shadow-2xl overflow-hidden"
             >
                <div className="absolute inset-0 bg-gradient-to-r from-[var(--color-accent)] to-[#AF52F2] opacity-0 group-hover:opacity-10 transition-opacity" />
                <div className="relative flex items-center gap-3">
                   <Maximize2 size={20} className="text-[var(--color-accent)]" />
                   {locale === 'ca' ? 'Presentació de Projectes' : 'Project Presentation'}
                </div>
             </Link>

             <Link
               href={`/v/${token}/move`}
               className="group px-8 py-4 bg-[var(--color-surface)] border border-[var(--color-border)] text-[var(--color-text)] font-bold rounded-2xl transition-all hover:border-[var(--color-accent)] hover:bg-[var(--color-accent-subtle)] flex items-center gap-3"
             >
                <div className="w-8 h-8 rounded-xl bg-[var(--color-accent)]/10 flex items-center justify-center text-[var(--color-accent)] group-hover:scale-110 transition-transform">
                   <Move size={18} />
                </div>
                <span>Move</span>
             </Link>
          </div>
        </div>
      </section>

      {/* Global PDF Presentation Overlay */}
      <PdfPresentationMode works={visibleWorks.filter(w => !!w.pdf_url) as any} />

      <div className="max-w-7xl mx-auto px-6 pb-32">

        {/* 2. PORTFOLIO FEED (Search + Filtered Works Grid) */}
        { }
        <PortfolioFeed 
          works={visibleWorks.map(w => ({
            ...w,
            /* eslint-disable-next-line @typescript-eslint/no-explicit-any */
            companies: Array.isArray(w.companies) ? w.companies[0] : (w.companies as any)
          })) as any} 
          token={token}
          locale={locale}
          initialCompanyId={companyId}
          companies={allCompanies || []}
        />

        {/* 3. TRUSTED BY / CLIENTS (Compact Activity Style) */}
        {projectClients.length > 0 && (
          <section className="mt-40 border-t border-[var(--color-border)] pt-20">
            <div className="flex flex-col md:flex-row gap-16 md:gap-24">
              <div className="w-full md:w-[320px] shrink-0">
                <h2 className="text-sm font-black uppercase tracking-[0.4em] text-[var(--color-muted)] mb-6">
                  {t("collaborations_title")}
                </h2>
                <p className="text-sm text-[var(--color-muted)] leading-relaxed opacity-80">
                  {t("collaborations_desc")}
                </p>
                <div className="mt-10">
                  <a href={`/v/${token}/cv`} className="inline-flex items-center gap-2 px-6 py-3 rounded-xl bg-[var(--color-surface)] border border-[var(--color-border)] text-sm font-bold text-[var(--color-text)] hover:border-[var(--color-accent)] hover:text-[var(--color-accent)] hover:bg-[var(--color-accent-subtle)] hover:shadow-[0_0_20px_var(--color-accent-glow)] transition-all duration-300">
                    {t("view_cv")} <span className="ml-1 opacity-50">&rarr;</span>
                  </a>
                </div>
              </div>

              <div className="flex-1 grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
                {projectClients.map((company) => (
                  <div key={company.slug} className="flex flex-col items-center gap-3 group text-center p-2">
                    <div className="relative w-24 h-24    flex items-center justify-center overflow-hidden shrink-0 transition-all duration-500 group-hover:scale-105   ">
                      {company.logo_url ? (
                        <Image 
                          src={company.logo_url} 
                          alt={company.name} 
                          fill 
                          className="object-cover grayscale group-hover:grayscale-0 transition-all duration-500 opacity-80 group-hover:opacity-100" 
                        />
                      ) : (
                        <span className="text-[var(--color-muted)] text-2xl font-black group-hover:text-[var(--color-accent)] transition-colors">{company.name.charAt(0)}</span>
                      )}
                    </div>
                    <div className="space-y-1">
                      <h4 className="text-xs font-black uppercase tracking-widest text-[var(--color-text)] opacity-60 group-hover:opacity-100 transition-opacity">{company.name}</h4>
                      <p className="text-[9px] text-[var(--color-muted)] font-bold uppercase tracking-[0.2em]">{company.sector}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </section>
        )}

      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { getLocale } from "next-intl/server";
import Image from "next/image";
import { Mail, Link2, Globe, MapPin, ExternalLink } from "lucide-react";
import { generateHTML } from "@tiptap/html";
import StarterKit from "@tiptap/starter-kit";
import ImageExtension from "@tiptap/extension-image";
import LinkExtension from "@tiptap/extension-link";
import Underline from "@tiptap/extension-underline";

export default async function AboutMePage({ params }: { params: Promise<{ token: string }> }) {
  await params;
  const locale = await getLocale();
  const supabase = await createClient();

  const ADMIN_PROFILE_ID = "00000000-0000-0000-0000-000000000000";
  const { data: about } = await supabase
    .from("about_me")
    .select("*")
    .eq("id", ADMIN_PROFILE_ID)
    .maybeSingle();

  if (!about) {
    return (
      <div className="max-w-4xl mx-auto px-6 py-20 text-center text-[var(--color-muted)]">
        Informació no disponible
      </div>
    );
  }

  const bioData = about.bio ? about.bio[locale] || about.bio["ca"] : "";
  let bioHtml = "";

  if (typeof bioData === "string") {
    bioHtml = bioData;
  } else if (bioData && typeof bioData === "object") {
    try {
      bioHtml = generateHTML(bioData as object, [
        StarterKit,
        ImageExtension,
        LinkExtension,
        Underline,
      ]);
    } catch (err: unknown) {
      console.error("Error parsing bio JSON:", err);
      bioHtml = "";
    }
  }

  const contactLinks = [
    {
      label: "Email Directo",
      value: "info@descobreix.com",
      link: "mailto:info@descobreix.com",
      icon: <Mail className="w-5 h-5" />
    },
    {
      label: "LinkedIn",
      value: "Professional Profile",
      link: about.social_links?.linkedin || "https://linkedin.com",
      icon: <Link2 className="w-5 h-5" />
    },
    {
      label: "Ubicació",
      value: "Baix Llobregat, Anoia, Barcelonès i Vallès Occidental",
      link: null,
      icon: <MapPin className="w-5 h-5" />
    }
  ];

  return (
    <div className="max-w-4xl mx-auto px-6 py-16 animate-in fade-in duration-500">
      {/* 1. Header & Intro */}
      <div className="flex flex-col md:flex-row gap-6 md:gap-12 items-start mb-16 border-b border-[var(--color-border)] pb-8 relative">
        <div className="flex-1">
          <h1 className="text-5xl md:text-7xl font-display font-black text-[var(--color-text)] tracking-tight mb-2">
            {about.name || "Marc"}
          </h1>
          <p className="text-xl md:text-2xl text-[var(--color-accent)] font-bold tracking-tight">
            {about.tagline || ""}
          </p>
        </div>

        {about.photo_url && (
          <div className="relative w-32 h-32 md:w-48 md:h-48 rounded-3xl overflow-hidden shrink-0 border-2 border-[var(--color-border)] shadow-2xl rotate-3">
            <Image src={about.photo_url} alt="Profile" fill className="object-cover" />
          </div>
        )}
      </div>

      {/* 2. Bio Section */}
      <div className="mb-24">
        <div 
          className="text-[var(--color-text-subtle)] leading-relaxed text-lg space-y-4 prose prose-invert max-w-none prose-p:text-[var(--color-text-subtle)] prose-strong:text-[var(--color-accent)]"
          dangerouslySetInnerHTML={{ __html: typeof bioHtml === "string" ? bioHtml : "" }}
        />
      </div>

      {/* 3. Contact Integrated Section */}
      <div className="pt-16 border-t border-[var(--color-border)]">
        <h2 className="text-3xl font-display font-black text-[var(--color-text)] mb-8 tracking-tight">Contacte i Xarxes</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {contactLinks.map((c, i) => (
            <div key={i} className="bg-[var(--color-surface)] border border-[var(--color-border)] p-6 rounded-2xl flex items-center gap-5 hover:border-[var(--color-accent)]/40 transition-all group">
               <div className="p-3 bg-[var(--color-bg)] rounded-xl text-[var(--color-accent)]">
                 {c.icon}
               </div>
               <div className="flex-1">
                 <p className="text-[var(--color-muted)] text-[10px] uppercase font-black tracking-widest mb-0.5">{c.label}</p>
                 {c.link ? (
                   <a href={c.link} target="_blank" rel="noopener noreferrer" className="text-[var(--color-text)] font-bold text-sm flex items-center gap-1.5 hover:text-[var(--color-accent)] transition-colors">
                     {c.value}
                     <ExternalLink className="w-3 h-3 opacity-30" />
                   </a>
                 ) : (
                   <span className="text-[var(--color-text)] font-bold text-sm block">{c.value}</span>
                 )}
               </div>
            </div>
          ))}
        </div>

        {/* 4. Treballem Junts CTA */}
        <div className="mt-12 p-8 md:p-10 bg-gradient-to-br from-[var(--color-accent-subtle)] to-transparent border border-[var(--color-accent)]/20 rounded-3xl flex flex-col md:flex-row gap-8 items-center justify-between">
           <div>
             <h4 className="text-[var(--color-text)] font-display text-2xl font-black mb-2 tracking-tight">Treballem junts</h4>
             <p className="text-[var(--color-muted)] text-sm max-w-sm leading-relaxed">Si creus que el meu perfil encaixa amb el que busques, escriu-me i et respondré el més aviat possible.</p>
           </div>
           <a 
             href="mailto:info@descobreix.com" 
             className="shrink-0 bg-[var(--color-accent)] hover:bg-[var(--color-accent-hover)] text-white px-8 py-4 rounded-xl font-bold shadow-lg shadow-[var(--color-accent-glow)] transition-all hover:scale-105 active:scale-95"
           >
             Enviar Correu Electrònic
           </a>
        </div>
      </div>
    </div>
  );
}

import { createClient } from "@/lib/supabase/server";
import { notFound } from "next/navigation";
import Image from "next/image";
import Link from "next/link";
import { Lock, FileText, Maximize } from "lucide-react";
import { generateHTML } from "@tiptap/html";
import StarterKit from "@tiptap/starter-kit";
import ImageExtension from "@tiptap/extension-image";
import LinkExtension from "@tiptap/extension-link";
import Underline from "@tiptap/extension-underline";
import { PinGateWrapper } from "@/components/portfolio/PinGateWrapper";
import { BackButton } from "@/components/portfolio/BackButton";
import { VideoNode, AudioNode, IframeNode } from "@/components/admin/TipTapExtensions";
import { clsx } from "clsx";

export default async function WorkPage({
  params,
  searchParams: _searchParams,
}: {
  params: Promise<{ token: string; slug: string }>;
  searchParams: Promise<{ [key: string]: string | string[] | undefined }>;
}) {
  const { token, slug } = await params;

  const supabase = await createClient();

  // Obtain work info
  const { data: work, error } = await supabase
    .from("works")
    .select("*, companies (name, is_freelance)")
    .eq("slug", slug)
    .single();

  if (error || !work || work.status !== "published") {
    notFound();
  }

  // Authorization token check
  const { data: tokenData } = await supabase
    .from("access_tokens")
    .select("company_ids, active")
    .eq("token", token)
    .maybeSingle();

  const isActive = tokenData?.active ?? false;

  // No longer blocking access to works by token validity here. 
  // Portfolio is now public. 

  if (tokenData && tokenData.active && tokenData.company_ids && tokenData.company_ids.length > 0) {
    // Note: work.companies is the joined company record
    if (!tokenData.company_ids.includes(work.company_id) && !work.companies?.is_freelance) {
      notFound();
    }
  }

  // -----------------------------------------
  // RENDER BLOCKS
  // -----------------------------------------
  const renderBlock = (block: any) => {
    const settings = block.settings || {};
    const content = block.content || {};

    const blockStyle = {
      backgroundColor: settings.backgroundColor || 'transparent',
      paddingTop: settings.padding || '0px',
      paddingBottom: settings.padding || '0px',
    };

    switch (block.type) {
      case 'text':
        let html = "";
        if (content.json) {
           html = generateHTML(content.json, [StarterKit, ImageExtension, LinkExtension, Underline, VideoNode, AudioNode, IframeNode]);
        } else if (content.text) {
           html = `<p>${content.text}</p>`;
        }
        return (
          <div key={block.id} style={blockStyle}>
            <div className={clsx("mx-auto px-6", settings.fullWidth ? "w-full" : "max-w-4xl")}>
              <article 
                className="prose prose-invert prose-lg max-w-none prose-p:text-[var(--color-muted)] prose-headings:text-[var(--color-text)]"
                dangerouslySetInnerHTML={{ __html: html }}
              />
            </div>
          </div>
        );

      case 'media':
        if (!content.url) return null;
        return (
          <div key={block.id} style={blockStyle}>
            <div className={clsx("mx-auto px-6", settings.fullWidth ? "w-full px-0" : "max-w-6xl")}>
               <div className={clsx("relative rounded-2xl overflow-hidden shadow-2xl border border-white/5", !settings.fullWidth && "aspect-video")}>
                  {content.mimeType?.startsWith('video') ? (
                    <video src={content.url} controls className="w-full h-full object-cover" />
                  ) : (
                    <img src={content.url} className="w-full h-full object-cover" alt="" />
                  )}
               </div>
            </div>
          </div>
        );

      case 'gallery':
        const items = content.items || [];
        if (items.length === 0) return null;
        return (
          <div key={block.id} style={blockStyle}>
            <div className={clsx("mx-auto px-6", settings.fullWidth ? "w-full px-0" : "max-w-7xl")}>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {items.map((url: string, idx: number) => (
                    <div key={idx} className="aspect-square rounded-2xl overflow-hidden border border-white/5 shadow-lg group">
                       <img 
                        src={url} 
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" 
                        alt="" 
                       />
                    </div>
                  ))}
               </div>
            </div>
          </div>
        );

      case 'pdf':
        if (!content.url) return null;
        if (content.display === 'embed') {
           return (
             <div key={block.id} style={blockStyle}>
               <div className={clsx("mx-auto px-6", settings.fullWidth ? "w-full px-0" : "max-w-6xl")}>
                  <div className="relative w-full aspect-[1/1.4] md:aspect-[1/1.4142] rounded-2xl overflow-hidden shadow-2xl border border-white/5 bg-black/20 group">
                     {/* Clean Viewer Wrapper */}
                     <iframe 
                       src={`${content.url}#toolbar=0&navpanes=0&scrollbar=0`}
                       className="w-full h-full border-none pointer-events-none md:pointer-events-auto"
                       title={content.title}
                     />

                     {/* Overlay for mobile or to provide a clean exit/open action */}
                     <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <a 
                          href={content.url} 
                          target="_blank" 
                          className="p-3 bg-black/60 backdrop-blur-xl text-white rounded-xl border border-white/10 hover:bg-[var(--color-accent)] transition-all"
                          title="Veure en pantalla completa"
                        >
                          <Maximize className="w-5 h-5" />
                        </a>
                     </div>
                  </div>
                  {content.description && (
                    <p className="mt-4 text-center text-sm text-[var(--color-muted)] max-w-2xl mx-auto italic">{content.description}</p>
                  )}
               </div>
             </div>
           );
        }
        return (
          <div key={block.id} style={blockStyle}>
            <div className="max-w-4xl mx-auto px-6">
               <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-3xl p-8 flex flex-col md:flex-row items-center gap-8 shadow-xl hover:border-[var(--color-accent)]/30 transition-all group">
                  <div className="w-20 h-20 rounded-2xl bg-red-500/10 flex items-center justify-center text-red-500 shrink-0 group-hover:scale-110 transition-transform">
                     <FileText size={40} />
                  </div>
                  <div className="flex-1 text-center md:text-left">
                     <p className="text-[10px] font-black uppercase tracking-[0.3em] text-[var(--color-muted)] mb-2">Documentació Oficial PDF</p>
                     <h3 className="text-xl font-bold text-[var(--color-text)] mb-2">{content.title}</h3>
                     {content.description && <p className="text-sm text-[var(--color-muted)] line-clamp-2">{content.description}</p>}
                  </div>
                  <a 
                    href={content.url} 
                    target="_blank" 
                    className="bg-[var(--color-accent)] text-white px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-widest shadow-lg shadow-[var(--color-accent-glow)] hover:scale-105 transition-all"
                  >
                    Obrir Document
                  </a>
               </div>
            </div>
          </div>
        );

      case 'spacer':
        return <div key={block.id} className="h-16 md:h-24" />;

      default:
        return null;
    }
  };

  // -----------------------------------------
  // FETCH NAVIGATION
  // -----------------------------------------
  let prevWork: { slug: string, title: string } | null = null;
  let nextWork: { slug: string, title: string } | null = null;

  const { data: rawWorks } = await supabase
    .from("works")
    .select("slug, title, company_id, companies (is_freelance)")
    .eq("status", "published")
    .order("work_date", { ascending: false });

  if (rawWorks) {
    let validWorks = rawWorks;
    if (tokenData?.company_ids && tokenData.company_ids.length > 0) {
      validWorks = validWorks.filter((w) => {
        const company = Array.isArray(w.companies) ? w.companies[0] : w.companies;
        return tokenData.company_ids!.includes(w.company_id) || (company as { is_freelance: boolean })?.is_freelance;
      });
    }

    const currentIndex = validWorks.findIndex(w => w.slug === slug);
    if (currentIndex !== -1) {
      // Orden DESC means prev is index + 1 (más antiguo), next is index - 1 (más nuevo)
      // Ajustamos la semántica: "Anterior" (más nuevo) -> index - 1, "Següent" (más antiguo) -> index + 1
      prevWork = currentIndex > 0 ? validWorks[currentIndex - 1] : null;
      nextWork = currentIndex < validWorks.length - 1 ? validWorks[currentIndex + 1] : null;
    }
  }

  const content = work.content || {};
  let htmlContent = "";
  if (content && typeof content === "object" && !Array.isArray(content)) {
    try {
      htmlContent = generateHTML(content as object, [
        StarterKit,
        ImageExtension,
        LinkExtension,
        Underline,
        VideoNode,
        AudioNode,
        IframeNode,
      ]);
    } catch (err) {
