          .prose h1, .prose h2, .prose h3 { color: var(--color-text); }
        `}} />
      )}
      {contentNode}
    </PinGateWrapper>
  );
}

"use client";

import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Image from "@tiptap/extension-image";
import Link from "@tiptap/extension-link";
import Underline from "@tiptap/extension-underline";
import CharacterCount from "@tiptap/extension-character-count";
import Placeholder from "@tiptap/extension-placeholder";
import { useRef, useState, useCallback } from "react";
import { Bold, Italic, Underline as UnderlineIcon, Link as LinkIcon, Image as ImageIcon, Heading1, Heading2, Quote, List, ListOrdered, Loader2, Upload, Film, Music, FileText } from "lucide-react";
import { createClient } from "@/lib/supabase/client";
import { VideoNode, AudioNode, IframeNode } from "./TipTapExtensions";

interface TipTapEditorProps {
  content: string | object | null;
  onChange: (json: object) => void;
}

export function TipTapEditor({ content, onChange }: TipTapEditorProps) {
  const [uploading, setUploading] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const editor = useEditor({
    extensions: [
      StarterKit.configure({ heading: { levels: [1, 2, 3] } }),
      Underline,
      Image.configure({
        HTMLAttributes: { class: 'rounded-xl border border-[var(--color-border)] shadow-lg my-6 max-w-full h-auto object-cover' },
      }),
      VideoNode,
      AudioNode,
      IframeNode,
      Link.configure({
        openOnClick: false,
        HTMLAttributes: { class: 'text-color-accent hover:text-color-accent-hover underline underline-offset-4 cursor-pointer' },
      }),
      Placeholder.configure({
        placeholder: "Escribe la descripción de este trabajo...",
        emptyEditorClass: 'is-editor-empty before:content-[attr(data-placeholder)] before:text-color-muted before:float-left before:h-0 before:pointer-events-none',
      }),
      CharacterCount,
    ],
    immediatelyRender: false,
    content,
    onUpdate: ({ editor }) => { onChange(editor.getJSON()); },
    editorProps: {
      attributes: {
        class: "prose dark:prose-invert prose-p:text-[var(--color-text)] prose-headings:font-serif prose-headings:text-[var(--color-text)] max-w-none focus:outline-none min-h-[400px] p-6 bg-[var(--color-bg)] rounded-b-xl border border-t-0 border-[var(--color-border)]",
      },
    },
  });

  const uploadMedia = useCallback(async (file: File) => {
    if (!editor) return;

    // Check if it's explicitly supported
    const isImage = file.type.startsWith("image/");
    const isVideo = file.type.startsWith("video/");
    const isAudio = file.type.startsWith("audio/");
    const isPdf = file.type === "application/pdf";

    if (!isImage && !isVideo && !isAudio && !isPdf) { 
      alert("Format no suportat. Usa imatges, vídeos, àudio o PDF."); 
      return; 
    }

    setUploading(true);
    try {
      const supabase = createClient();
      const ext = file.name.split(".").pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;
      const filePath = `works/${fileName}`;

      const { error } = await supabase.storage.from("portfolio-media").upload(filePath, file, { upsert: false });
      if (error) throw error;

      const { data } = supabase.storage.from("portfolio-media").getPublicUrl(filePath);

      if (isImage) {
        editor.chain().focus().setImage({ src: data.publicUrl }).run();
      } else if (isVideo) {
        editor.chain().focus().insertContent({ type: 'video', attrs: { src: data.publicUrl } }).run();
      } else if (isAudio) {
        editor.chain().focus().insertContent({ type: 'audio', attrs: { src: data.publicUrl } }).run();
      } else if (isPdf) {
        editor.chain().focus().insertContent({ type: 'iframe', attrs: { src: data.publicUrl, title: file.name } }).run();
      }

    } catch (err: unknown) {
      alert(`Error al pujar el fitxer: ${err instanceof Error ? err.message : String(err)}`);
    } finally {
      setUploading(false);
    }
  }, [editor]);

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) uploadMedia(file);
    e.target.value = "";
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const file = e.dataTransfer.files?.[0];
    if (file) uploadMedia(file);
  }, [uploadMedia]);

  const handleLink = () => {
    if (!editor) return;
    const previousUrl = editor.getAttributes("link").href;
    const url = window.prompt("URL del enlace", previousUrl);
    if (url === null) return;
    if (url === "") { editor.chain().focus().extendMarkRange("link").unsetLink().run(); return; }
    editor.chain().focus().extendMarkRange("link").setLink({ href: url }).run();
  };

  if (!editor) return null;

  const btn = (active: boolean) =>
    `p-2 rounded-lg transition-all ${active ? "bg-[var(--color-accent-subtle)] text-[var(--color-accent)] shadow-inner" : "text-[var(--color-muted)] hover:text-[var(--color-accent)] hover:bg-[var(--color-accent-subtle)]"}`;

  return (
    <div
      className={`flex flex-col shadow-xl rounded-xl relative transition-all duration-200 ${isDragging ? "ring-2 ring-color-accent ring-offset-2 ring-offset-color-bg" : ""}`}
      onDrop={handleDrop}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
    >
      {/* TOOLBAR */}
      <div className="flex items-center gap-1 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-t-xl px-4 py-3 sticky top-0 z-20 transition-colors overflow-x-auto whitespace-nowrap scrollbar-hide">
        <button type="button" onClick={() => editor.chain().focus().toggleBold().run()} className={btn(editor.isActive("bold"))}><Bold className="w-4 h-4" /></button>
        <button type="button" onClick={() => editor.chain().focus().toggleItalic().run()} className={btn(editor.isActive("italic"))}><Italic className="w-4 h-4" /></button>
        <button type="button" onClick={() => editor.chain().focus().toggleUnderline().run()} className={btn(editor.isActive("underline"))}><UnderlineIcon className="w-4 h-4" /></button>
        <div className="w-px h-6 bg-[var(--color-border)] mx-2" />
        <button type="button" onClick={() => editor.chain().focus().toggleHeading({ level: 1 }).run()} className={btn(editor.isActive("heading", { level: 1 }))}><Heading1 className="w-4 h-4" /></button>
        <button type="button" onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()} className={btn(editor.isActive("heading", { level: 2 }))}><Heading2 className="w-4 h-4" /></button>
        <div className="w-px h-6 bg-[var(--color-border)] mx-2" />
        <button type="button" onClick={() => editor.chain().focus().toggleBulletList().run()} className={btn(editor.isActive("bulletList"))}><List className="w-4 h-4" /></button>
        <button type="button" onClick={() => editor.chain().focus().toggleOrderedList().run()} className={btn(editor.isActive("orderedList"))}><ListOrdered className="w-4 h-4" /></button>
        <button type="button" onClick={() => editor.chain().focus().toggleBlockquote().run()} className={btn(editor.isActive("blockquote"))}><Quote className="w-4 h-4" /></button>
        <div className="w-px h-6 bg-[var(--color-border)] mx-2" />
        <button type="button" onClick={handleLink} className={btn(editor.isActive("link"))}><LinkIcon className="w-4 h-4" /></button>
        <button
          type="button"
          onClick={() => fileInputRef.current?.click()}
          disabled={uploading}
          className={`p-2 rounded-lg transition-all ${uploading ? "opacity-50 cursor-not-allowed text-[var(--color-muted)]" : "text-[var(--color-muted)] hover:text-[var(--color-accent)] hover:bg-[var(--color-accent-subtle)]"}`}
          title="Pujar mèdia (imatge, vídeo, àudio, PDF)"
        >
          {uploading ? <Loader2 className="w-4 h-4 animate-spin" /> : <div className="flex -space-x-1"><ImageIcon className="w-4 h-4" /><Film className="w-4 h-4 hidden sm:block" /></div>}
        </button>
        <input ref={fileInputRef} type="file" accept="image/*,video/*,audio/*,application/pdf" className="hidden" onChange={handleFileInput} />
      </div>

      {/* Drag overlay */}
      {isDragging && (
        <div className="absolute inset-0 z-20 flex items-center justify-center bg-color-bg/80 backdrop-blur-sm rounded-xl border-2 border-dashed border-color-accent pointer-events-none">
          <div className="text-center">
            <Upload className="w-10 h-10 text-color-accent mx-auto mb-2" />
            <p className="text-color-accent font-bold text-lg">Suelta para subir</p>
          </div>
        </div>
      )}

      <div className="relative"><EditorContent editor={editor} /></div>

      <div className="flex justify-between items-center px-4 py-2 bg-[var(--color-surface)] border border-t-0 border-[var(--color-border)] rounded-b-xl text-[10px] font-black uppercase tracking-widest text-[var(--color-muted)]">
        <span>{editor.storage.characterCount.characters()} caràcters</span>
        <span>{editor.storage.characterCount.words()} paraules</span>
      </div>
    </div>
  );
}

"use client";

import React, { useState, useCallback, useMemo } from 'react';
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
  DragEndEvent,
} from '@dnd-kit/core';
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
  useSortable,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { 
  Plus, 
  GripVertical, 
  Trash2, 
  Settings2, 
  Type, 
  Image as ImageIcon, 
  FileText, 
  LayoutGrid, 
  Maximize, 
  MoveHorizontal,
  Video as VideoIcon,
  Music,
  Check,
  Upload,
  Loader2
} from 'lucide-react';
import { clsx } from 'clsx';
import { TipTapEditor } from '../TipTapEditor';
import { createClient } from '@/lib/supabase/client';
import { Toast, ToastType } from '@/components/ui/Toast';

// Types
export type BlockType = 'text' | 'media' | 'pdf' | 'gallery' | 'spacer';

export interface Block {
  id: string;
  type: BlockType;
  content: any;
  settings: {
    backgroundColor?: string;
    padding?: string;
    fullWidth?: boolean;
    hidden?: boolean;
  };
}

interface BlockBuilderProps {
  blocks: Block[];
  onChange: (blocks: Block[]) => void;
  showNotification?: (message: string, type: ToastType) => void;
}

// SORTABLE WRAPPER
function SortableBlock({ 
  block, 
  onDelete, 
  onUpdateContent, 
  onUpdateSettings,
  isEditing,
  setEditingId,
  handleUpload
}: { 
  block: Block, 
  onDelete: () => void,
  onUpdateContent: (content: any) => void,
  onUpdateSettings: (settings: any) => void,
  isEditing: boolean,
  setEditingId: (id: string | null) => void,
  handleUpload: (file: File) => Promise<string>
}) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging
  } = useSortable({ id: block.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 100 : 1,
  };

  return (
    <div 
      ref={setNodeRef} 
      style={style} 
      className={clsx(
        "group relative border border-transparent hover:border-[var(--color-accent)]/30 rounded-2xl transition-all mb-4 bg-[var(--color-surface)]/30",
        isDragging && "opacity-50 scale-[0.98] shadow-2xl",
        isEditing && "border-[var(--color-accent)] ring-1 ring-[var(--color-accent)]/20"
      )}
    >
      {/* DRAG HANDLE & ACTIONS */}
      <div className="absolute -left-12 top-1/2 -translate-y-1/2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
        <div {...attributes} {...listeners} className="p-2 cursor-grab active:cursor-grabbing text-[var(--color-muted)] hover:text-[var(--color-accent)] bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg shadow-sm">
          <GripVertical size={16} />
        </div>
      </div>

      <div className="absolute -right-12 top-0 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
         <button 
          onClick={() => setEditingId(isEditing ? null : block.id)}
          className={clsx("p-2 border rounded-lg shadow-sm transition-all", isEditing ? "bg-[var(--color-accent)] text-white border-[var(--color-accent)]" : "bg-[var(--color-bg)] text-[var(--color-muted)] border-[var(--color-border)] hover:text-[var(--color-accent)]")}
         >
          <Settings2 size={16} />
         </button>
         <button 
          onClick={onDelete}
          className="p-2 bg-[var(--color-bg)] border border-[var(--color-border)] text-[var(--color-muted)] hover:text-red-500 rounded-lg shadow-sm transition-all"
         >
          <Trash2 size={16} />
         </button>
      </div>

      {/* BLOCK CONTENT RENDERER */}
      <div 
        className="p-1 min-h-[60px]"
        style={{ 
          backgroundColor: block.settings.backgroundColor || 'transparent',
          padding: block.settings.padding || '1rem' 
        }}
      >
        <div className={clsx(block.settings.fullWidth ? "w-full" : "max-w-4xl mx-auto")}>
          {renderBlockContent(block, onUpdateContent, isEditing, handleUpload)}
        </div>
      </div>

      {/* SETTINGS PANEL (INLINE) */}
      {isEditing && (
        <div className="border-t border-[var(--color-border)] p-4 bg-[var(--color-bg)]/80 rounded-b-2xl animate-in fade-in slide-in-from-top-2 duration-300">
           <div className="flex flex-wrap gap-6 items-center">
              <div>
                 <label className="block text-[9px] font-black uppercase tracking-widest text-[var(--color-muted)] mb-2">Fons Secció</label>
                 <div className="flex gap-2">
                    {['transparent', 'var(--color-surface)', 'var(--color-accent-subtle)', '#000000'].map(c => (
                      <button 
                        key={c}
                        onClick={() => onUpdateSettings({ ...block.settings, backgroundColor: c })}
                        className={clsx("w-6 h-6 rounded-full border border-white/10 relative", block.settings.backgroundColor === c && "ring-2 ring-[var(--color-accent)] ring-offset-2 ring-offset-[var(--color-bg)]")}
                        style={{ backgroundColor: c }}
                      >
                        {block.settings.backgroundColor === c && <Check size={10} className="absolute inset-0 m-auto text-[var(--color-accent)]" />}
                      </button>
                    ))}
                 </div>
              </div>

              <div>
                 <label className="block text-[9px] font-black uppercase tracking-widest text-[var(--color-muted)] mb-2">Espaiat (Padding)</label>
                 <select 
                   value={block.settings.padding}
                   onChange={(e) => onUpdateSettings({ ...block.settings, padding: e.target.value })}
                   className="bg-[var(--color-bg)] border border-[var(--color-border)] text-[10px] rounded-lg px-3 py-1.5 outline-none focus:border-[var(--color-accent)]"
                 >
                    <option value="1rem">Petit</option>
                    <option value="2.5rem">Normal</option>
                    <option value="5rem">Gran</option>
                    <option value="0">Sense espai</option>
                 </select>
              </div>

              <div className="flex gap-4">
                 <label className="flex items-center gap-2 cursor-pointer group">
                    <input 
                      type="checkbox" 
                      checked={block.settings.fullWidth} 
                      onChange={(e) => onUpdateSettings({ ...block.settings, fullWidth: e.target.checked })}
                      className="peer appearance-none w-4 h-4 border border-[var(--color-border)] rounded checked:bg-[var(--color-accent)]" 
                    />
                    <span className="text-[10px] font-black uppercase tracking-widest text-[var(--color-muted)] group-hover:text-white">Ample Total</span>
                 </label>
              </div>
           </div>
        </div>
      )}
    </div>
  );
}

function renderBlockContent(
  block: Block, 
  onUpdate: (content: any) => void, 
  isEditing: boolean,
  handleUpload: (file: File) => Promise<string>
) {
  // Inner upload handling removed - now passed from parent

  switch (block.type) {
    case 'text':
      return (
        <div className="bg-[var(--color-bg)] rounded-xl border border-[var(--color-border)] overflow-hidden">
           <TipTapEditor 
             content={block.content.json || block.content.text || ""} 
             onChange={(json) => onUpdate({ ...block.content, json })} 
           />
        </div>
      );
    case 'media':
      return (
        <div className="group relative">
           {block.content.url ? (
             <div className="rounded-2xl overflow-hidden border border-[var(--color-border)] shadow-xl bg-black/20 aspect-video flex items-center justify-center">
                {block.content.mimeType?.startsWith('video') ? (
                  <video src={block.content.url} controls className="w-full h-full object-cover" />
                ) : (
                  <img src={block.content.url} className="w-full h-full object-cover" alt="" />
                )}
                {isEditing && (
                  <button 
                    onClick={() => onUpdate({ ...block.content, url: null })}
                    className="absolute top-4 right-4 p-2 bg-red-500 text-white rounded-full shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <Trash2 size={16} />
                  </button>
                )}
             </div>
           ) : (
             <label className="flex flex-col items-center gap-4 py-12 border-2 border-dashed border-[var(--color-border)] rounded-3xl cursor-pointer hover:border-[var(--color-accent)] hover:bg-[var(--color-accent)]/5 transition-all">
                <input 
                  type="file" 
                  className="hidden" 
                  accept="image/*,video/*"
                  onChange={async (e) => {
                    const file = e.target.files?.[0];
                    if (file) {
                      const url = await handleUpload(file);
                      onUpdate({ ...block.content, url, mimeType: file.type });
                    }
                  }}
                />
                <Upload className="text-[var(--color-muted)] animate-bounce" size={32} />
                <div className="text-center">
                  <p className="text-xs font-black uppercase tracking-widest text-[var(--color-text)]">Pujar Mèdia</p>
                  <p className="text-[10px] text-[var(--color-muted)]">Imatges o Vídeos</p>
                </div>
             </label>
           )}
        </div>
      );
    case 'gallery':
      const items = block.content.items || [];
      return (
        <div className="space-y-4">
           {items.length > 0 ? (
             <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                {items.map((url: string, idx: number) => (
                  <div key={idx} className="aspect-square rounded-xl overflow-hidden border border-[var(--color-border)] relative group">
                     <img src={url} className="w-full h-full object-cover" alt="" />
                     {isEditing && (
                       <button 
                        onClick={() => onUpdate({ ...block.content, items: items.filter((_: any, i: number) => i !== idx) })}
                        className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-lg opacity-0 group-hover:opacity-100 transition-all"
                       >
                         <Trash2 size={12} />
                       </button>
                     )}
                  </div>
                ))}
                {isEditing && (
                  <label className="aspect-square rounded-xl border-2 border-dashed border-[var(--color-border)] flex flex-col items-center justify-center gap-2 cursor-pointer hover:border-[var(--color-accent)] hover:bg-[var(--color-accent)]/5 transition-all">
                     <Plus size={20} className="text-[var(--color-muted)]" />
                     <input 
                       type="file" 
                       multiple 
                       className="hidden" 
                       accept="image/*" 
                       onChange={async (e) => {
                         const files = Array.from(e.target.files || []);
                         const urls = await Promise.all(files.map(handleUpload));
                         onUpdate({ ...block.content, items: [...items, ...urls] });
                       }}
                     />
                  </label>
                )}
             </div>
           ) : (
              <label className="flex flex-col items-center gap-4 py-12 border-2 border-dashed border-[var(--color-border)] rounded-3xl cursor-pointer hover:border-[var(--color-accent)] hover:bg-[var(--color-accent)]/5 transition-all">
                <input 
                  type="file" 
                  multiple 
                  className="hidden" 
                  accept="image/*"
                  onChange={async (e) => {
                    const files = Array.from(e.target.files || []);
                    const urls = await Promise.all(files.map(handleUpload));
                    onUpdate({ ...block.content, items: urls });
                  }}
                />
                <LayoutGrid className="text-[var(--color-muted)]" size={32} />
                <div className="text-center">
                  <p className="text-xs font-black uppercase tracking-widest text-[var(--color-text)]">Crear Galeria</p>
                  <p className="text-[10px] text-[var(--color-muted)]">Selecciona múltiples imatges</p>
                </div>
              </label>
           )}
        </div>
      );
    case 'pdf':
      return (
        <div className="bg-[var(--color-surface-2)] border border-[var(--color-border)] rounded-2xl p-6 flex flex-col gap-4 shadow-sm hover:border-[var(--color-accent)]/30 transition-all">
           <div className="flex items-center gap-6">
              <div className="w-12 h-12 rounded-xl bg-red-500/10 flex items-center justify-center text-red-500 shrink-0">
                 <FileText size={24} />
              </div>
              <div className="flex-1 min-w-0">
                 <p className="text-[10px] font-black uppercase tracking-[0.2em] text-[var(--color-muted)] mb-1">Document PDF</p>
                 {block.content.url ? (
                   <input 
                     type="text" 
                     value={block.content.title || ""} 
                     onChange={(e) => onUpdate({ ...block.content, title: e.target.value })}
                     placeholder="Títol del document..."
                     className="w-full bg-transparent border-none text-sm font-bold text-[var(--color-text)] focus:outline-none p-0"
                   />
                 ) : (
                   <p className="text-sm font-bold text-[var(--color-muted)]">Cap fitxer seleccionat</p>
                 )}
              </div>
              {!block.content.url ? (
                <label className="bg-[var(--color-accent)] text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest cursor-pointer shadow-lg shadow-[var(--color-accent-glow)]">
                   Pujar PDF
                   <input 
                     type="file" 
                     className="hidden" 
                     accept="application/pdf"
                     onChange={async (e) => {
                       const file = e.target.files?.[0];
                       if (file) {
                         const url = await handleUpload(file);
                         onUpdate({ ...block.content, url, title: file.name.replace('.pdf', '') });
                       }
                     }}
                   />
                </label>
              ) : (
                <button 
                  onClick={() => onUpdate({ ...block.content, url: null })}
                  className="text-red-500 hover:bg-red-500/10 p-2 rounded-lg transition-colors"
                >
                  <Trash2 size={16} />
                </button>
              )}
           </div>

           {block.content.url && isEditing && (
             <div className="mt-2 pt-4 border-t border-[var(--color-border)]/50 space-y-4">
                <div>
                   <label className="block text-[9px] font-black uppercase tracking-widest text-[var(--color-muted)] mb-2">Descripció</label>
                   <textarea 
                     value={block.content.description || ""}
                     onChange={(e) => onUpdate({ ...block.content, description: e.target.value })}
                     placeholder="Descripció breu del document (opcional)..."
                     className="w-full bg-[var(--color-bg)]/50 border border-[var(--color-border)] rounded-lg p-3 text-[10px] text-[var(--color-muted)] outline-none focus:border-[var(--color-accent)] resize-none"
                     rows={2}
                   />
                </div>
                <div>
                   <label className="block text-[9px] font-black uppercase tracking-widest text-[var(--color-muted)] mb-2">Estil de Visualització</label>
                   <div className="flex gap-2">
                      <button 
                        onClick={() => onUpdate({ ...block.content, display: 'card' })}
                        className={clsx("flex-1 px-3 py-2 rounded-lg text-[10px] font-bold border transition-all", (block.content.display || 'card') === 'card' ? "bg-[var(--color-accent)] text-white border-[var(--color-accent)]" : "bg-[var(--color-bg)] text-[var(--color-muted)] border-[var(--color-border)]")}
                      >
                        Targeta Premium
                      </button>
                      <button 
                        onClick={() => onUpdate({ ...block.content, display: 'embed' })}
                        className={clsx("flex-1 px-3 py-2 rounded-lg text-[10px] font-bold border transition-all", block.content.display === 'embed' ? "bg-[var(--color-accent)] text-white border-[var(--color-accent)]" : "bg-[var(--color-bg)] text-[var(--color-muted)] border-[var(--color-border)]")}
                      >
                        Document Net (Embed)
                      </button>
                   </div>
                </div>
             </div>
           )}
        </div>
      );
    case 'spacer':
       return isEditing ? (
         <div className="flex flex-col items-center gap-2 py-4">
            <div className="w-full h-px bg-gradient-to-r from-transparent via-[var(--color-border)] to-transparent" />
            <span className="text-[9px] font-black uppercase tracking-widest text-[var(--color-muted)]">Espai Separador</span>
         </div>
       ) : <div className="h-4" />;
    default:
      return <div className="text-red-500 text-xs text-center p-4">Bloc no suportat: {block.type}</div>;
  }
}

// MAIN COMPONENT
export function BlockBuilder({ blocks, onChange }: BlockBuilderProps) {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  const showNotification = (message: string, type: ToastType) => {
    setToast({ message, type });
  };

  const handleUpload = async (file: File) => {
    const supabase = createClient();
    const ext = file.name.split(".").pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;
    const filePath = `blocks/${fileName}`;

    showNotification("Pujant fitxer...", "loading");

    try {
      const { error } = await supabase.storage.from("portfolio-media").upload(filePath, file);
      if (error) throw error;

      const { data } = supabase.storage.from("portfolio-media").getPublicUrl(filePath);
      showNotification("Fitxer pujat correctament!", "success");
      return data.publicUrl;
    } catch (err) {
      console.error(err);
      showNotification("Error en la pujada", "error");
      throw err;
    }
  };

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      const oldIndex = blocks.findIndex((b) => b.id === active.id);
      const newIndex = blocks.findIndex((b) => b.id === over.id);
      onChange(arrayMove(blocks, oldIndex, newIndex));
    }
  };

  const addBlock = (type: BlockType) => {
    const newBlock: Block = {
      id: Math.random().toString(36).slice(2, 9),
      type,
      content: type === 'text' ? { text: "" } : {},
      settings: {
        backgroundColor: 'transparent',
        padding: '2.5rem',
        fullWidth: false
      }
    };
    onChange([...blocks, newBlock]);
    setEditingId(newBlock.id);
  };

  const deleteBlock = (id: string) => {
    onChange(blocks.filter(b => b.id !== id));
  };

  const updateBlock = (id: string, updates: Partial<Block>) => {
    onChange(blocks.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  return (
    <div className="max-w-5xl mx-auto py-12">
      {toast && (
        <Toast 
          message={toast.message} 
          type={toast.type} 
          onClose={() => setToast(null)} 
        />
      )}
      <DndContext 
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleDragEnd}
      >
        <SortableContext 
          items={blocks.map(b => b.id)}
          strategy={verticalListSortingStrategy}
        >
          <div className="space-y-2">
            {blocks.map((block) => (
              <SortableBlock 
                key={block.id} 
                block={block} 
                onDelete={() => deleteBlock(block.id)}
                onUpdateContent={(content) => updateBlock(block.id, { content })}
                onUpdateSettings={(settings) => updateBlock(block.id, { settings })}
                isEditing={editingId === block.id}
                setEditingId={setEditingId}
                handleUpload={handleUpload}
              />
            ))}
          </div>
        </SortableContext>
      </DndContext>

      {/* ADD BLOCK BUTTONS */}
      <div className="mt-12 p-8 border-2 border-dashed border-[var(--color-border)] rounded-3xl flex flex-col items-center bg-[var(--color-bg)]/30">
         <span className="text-[10px] font-black uppercase tracking-[0.3em] text-[var(--color-muted)] mb-8">Afegir nou mòdul de contingut</span>
         <div className="flex flex-nowrap sm:flex-wrap justify-start sm:justify-center gap-4 w-full overflow-x-auto pb-4 scrollbar-hide">
            {[
              { type: 'text', label: 'Paràgraf', icon: Type },
              { type: 'media', label: 'Imatge/Vídeo', icon: ImageIcon },
              { type: 'gallery', label: 'Galeria', icon: LayoutGrid },
              { type: 'pdf', label: 'Document PDF', icon: FileText },
              { type: 'spacer', label: 'Separador', icon: MoveHorizontal },
            ].map((tool) => (
              <button
                key={tool.type}
                onClick={() => addBlock(tool.type as BlockType)}
                className="flex flex-col items-center gap-3 px-6 py-5 bg-[var(--color-surface)] border border-[var(--color-border)] hover:border-[var(--color-accent)] hover:bg-[var(--color-accent)]/5 rounded-2xl transition-all group w-32 shrink-0"
              >
                <div className="w-10 h-10 rounded-xl bg-[var(--color-bg)] flex items-center justify-center text-[var(--color-muted)] group-hover:text-[var(--color-accent)] group-hover:scale-110 transition-all border border-[var(--color-border)]">
                   <tool.icon size={20} />
                </div>
                <span className="text-[10px] font-black uppercase tracking-widest text-[var(--color-muted)] group-hover:text-[var(--color-text)]">{tool.label}</span>
              </button>
            ))}
         </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, useMemo } from "react";
import { X, Plus, Check, ChevronRight, ChevronLeft, MapPin, Calendar, Clock, BarChart3, Info, Loader2, Mountain, Waves, Zap, Flag, Music, Users, Cpu, Utensils, Beer, Search, Trash2, Map, MessageCircle, Lock } from "lucide-react";
import { clsx } from "clsx";
import { saveActivity, deleteActivity, geocodeLocation } from "@/app/actions/activities";
import { getSubcategories, addSubcategory, deleteSubcategory } from "@/app/actions/subcategories";
import { saveCategory, deleteCategory } from "@/app/actions/move_categories";
import { useRouter } from "next/navigation";
import { createPortal } from "react-dom";
import dynamic from "next/dynamic";
import { Toast, ToastType } from "../ui/Toast";

const LocationPicker = dynamic(() => import("./LocationPicker"), { 
  ssr: false,
  loading: () => <div className="fixed inset-0 z-[10000] bg-black/40 backdrop-blur-sm flex items-center justify-center"><Loader2 className="animate-spin text-white" size={32} /></div>
});

interface Category {
  id: string;
  name: string;
  group_id: string;
}

interface Group {
  id: string;
  name: string;
  icon_key: string;
  accent_color: string;
}

const ICON_MAP: Record<string, React.ElementType> = {
  Mountain,
  Waves,
  Zap,
  Flag,
  Music,
  Users,
  Cpu,
  Utensils,
  Beer,
  Search
};

interface ActivityModalProps {
  isOpen: boolean;
  onClose: () => void;
  groups: Group[];
  categories: Category[];
  editActivity?: any;
  initialDate?: Date;
}

export function ActivityModal({ isOpen, onClose, groups, categories, editActivity, initialDate }: ActivityModalProps) {
  const [step, setStep] = useState<'group' | 'category' | 'details'>('group');
  const [selectedGroup, setSelectedGroup] = useState<Group | null>(null);
  const [selectedCategory, setSelectedCategory] = useState<Category | null>(null);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isGeocoding, setIsGeocoding] = useState(false);
  const [isMapOpen, setIsMapOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string; type: ToastType } | null>(null);

  // Subcategories management
  const [subcategories, setSubcategories] = useState<any[]>([]);
  const [newSubName, setNewSubName] = useState("");
  const [isManagingSubs, setIsManagingSubs] = useState(false);
  const [isLoadingSubs, setIsLoadingSubs] = useState(false);

  // Category management
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [editingCategoryId, setEditingCategoryId] = useState<string | null>(null);
  const [categoryName, setCategoryName] = useState("");
  const [isSavingCategory, setIsSavingCategory] = useState(false);

  const router = useRouter();

  const filteredCategories = useMemo(() => {
    return categories.filter(c => {
      const matchesGroup = selectedGroup ? c.group_id === selectedGroup.id : true;
      const matchesSearch = c.name.toLowerCase().includes(search.toLowerCase());
      return matchesGroup && matchesSearch;
    });
  }, [categories, selectedGroup, search]);

  const showNotification = (message: string, type: ToastType) => {
    setToast({ message, type });
  };

  const [formData, setFormData] = useState({
    id: "",
    title: "",
    description: "",
    date: new Date().toISOString().split('T')[0],
    time: "10:00",
    endTime: "",
    isAllDay: false,
    location: "",
    lat: "",
    lng: "",
    distance: "",
    elevation: "",
    difficulty: "",
    whatsapp_link: "",
    subcategory_id: "",
    isLocked: false,
    unlockAt: ""
  });

  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  useEffect(() => {
    if (isOpen) {
      if (editActivity) {
        setStep('details');

        const cat = categories.find(c => c.id === editActivity.category_id);
        setSelectedCategory(cat || null);
        if (cat) {
           const grp = groups.find(g => g.id === cat.group_id);
           setSelectedGroup(grp || null);
        }

        const dateObj = new Date(editActivity.start_datetime);
        const yyyy = dateObj.getFullYear();
        const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
        const dd = String(dateObj.getDate()).padStart(2, '0');

        const HH = String(dateObj.getHours()).padStart(2, '0');
        const MM = String(dateObj.getMinutes()).padStart(2, '0');

        setFormData({
          id: editActivity.id,
          title: editActivity.title || "",
          description: editActivity.description || "",
          date: `${yyyy}-${mm}-${dd}`,
          time: `${HH}:${MM}`,
          endTime: editActivity.end_datetime ? `${String(new Date(editActivity.end_datetime).getHours()).padStart(2, '0')}:${String(new Date(editActivity.end_datetime).getMinutes()).padStart(2, '0')}` : "",
          isAllDay: editActivity.metadata?.isAllDay || false,
          location: editActivity.location || "",
          lat: editActivity.location_coords?.lat?.toString() || "",
          lng: editActivity.location_coords?.lng?.toString() || "",
          distance: editActivity.metadata?.distance?.toString() || "",
          elevation: editActivity.metadata?.elevation?.toString() || "",
          difficulty: editActivity.metadata?.difficulty || "",
          whatsapp_link: editActivity.whatsapp_link || "",
          subcategory_id: editActivity.subcategory_id || "",
          isLocked: editActivity.metadata?.isLocked || false,
          unlockAt: editActivity.metadata?.unlockAt || ""
        });
      } else {
        setStep('group');
        setSelectedGroup(null);
        setSelectedCategory(null);
        setSearch("");

        const d = initialDate || new Date();
        const yyyy = d.getFullYear();
        const mm = String(d.getMonth() + 1).padStart(2, '0');
        const dd = String(d.getDate()).padStart(2, '0');

        setFormData({
          id: "",
          title: "",
          description: "",
          date: `${yyyy}-${mm}-${dd}`,
          time: "10:00",
          endTime: "",
          isAllDay: false,
          location: "",
          lat: "",
          lng: "",
          distance: "",
          elevation: "",
          difficulty: "",
          whatsapp_link: "",
          subcategory_id: "",
          isLocked: false,
          unlockAt: ""
        });
      }
    }
  }, [isOpen, editActivity, initialDate, categories, groups]);

  // Handle category change: fetch subcategories
  useEffect(() => {
    if (selectedCategory) {
      const fetchSubs = async () => {
        setIsLoadingSubs(true);
        const res = await getSubcategories(selectedCategory.id);
        if (res.success) setSubcategories(res.data || []);
        setIsLoadingSubs(false);
      };
      fetchSubs();
    }
  }, [selectedCategory]);

  const handleAddSub = async () => {
    if (!selectedCategory || !newSubName.trim()) return;
    const res = await addSubcategory(selectedCategory.id, newSubName.trim());
    if (res.success) {
      setSubcategories([...subcategories, res.data]);
      setNewSubName("");
      showNotification("Subcategoria afegida", "success");
    } else {
      showNotification("Error: " + res.error, "error");
    }
  };

  const handleDelSub = async (id: string) => {
    if (!confirm("Eliminar aquesta subcategoria?")) return;
    const res = await deleteSubcategory(id);
    if (res.success) {
      setSubcategories(subcategories.filter(s => s.id !== id));
      if (formData.subcategory_id === id) setFormData({ ...formData, subcategory_id: "" });
      showNotification("Subcategoria eliminada", "success");
    }
  };

  const handleSaveCategory = async () => {
    if (!selectedGroup || !categoryName.trim()) return;
    setIsSavingCategory(true);
    showNotification("Guardant categoria...", "loading");

    const res = await saveCategory(categoryName.trim(), selectedGroup.id, editingCategoryId || undefined);
    if (res.success) {
      showNotification("Categoria guardada", "success");
      setIsAddingCategory(false);
      setEditingCategoryId(null);
      setCategoryName("");
      router.refresh();
    } else {
      showNotification("Error: " + res.error, "error");
    }
    setIsSavingCategory(false);
  };

  const handleDeleteCategory = async (id: string) => {
    if (!confirm("Estàs segur d'eliminar aquesta categoria?")) return;
    const res = await deleteCategory(id);
    if (res.success) {
      showNotification("Categoria eliminada", "success");
      router.refresh();
    } else {
      showNotification(res.error || "No s'ha pogut eliminar", "error");
    }
  };

  const handleSave = async () => {
    if (!selectedCategory) return;
    setLoading(true);
    showNotification("Guardant activitat...", "loading");
    try {
      const activityData = {
        ...formData,
        location_coords: (formData.lat && formData.lng) 
           ? { lat: parseFloat(formData.lat), lng: parseFloat(formData.lng) } 
           : null
      };

      const res = await saveActivity(activityData, selectedCategory.id);
      if (res.success) {
        showNotification("Activitat guardada correctament", "success");
        onClose();
      } else {
        showNotification("Error guardant: " + res.error, "error");
      }
    } catch (e) {
      showNotification("Error crític en desar", "error");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!formData.id || !confirm("Estàs segur d'eliminar aquesta activitat permanentment?")) return;
    setIsDeleting(true);
    showNotification("Eliminant activitat...", "loading");
    try {
      const res = await deleteActivity(formData.id);
      if (res.success) {
        showNotification("Activitat eliminada", "success");
        onClose();
      } else {
        showNotification("Error eliminant: " + res.error, "error");
      }
    } catch (e) {
      showNotification("Error crític en eliminar", "error");
    } finally {
      setIsDeleting(false);
    }
  };

  const handleGeocode = async () => {
    if (!formData.location) return;
    setIsGeocoding(true);
    showNotification("Cercant coordenades...", "loading");
    try {
       const res = await geocodeLocation(formData.location);
       if (res.success) {
          setFormData(prev => ({ ...prev, lat: res.lat, lng: res.lng }));
          showNotification("Ubicació trobada!", "success");
       } else {
          showNotification("No s'ha pogut trobar la ubicació.", "error");
       }
    } catch (e) {
       showNotification("Error de connexió geolocalitzant.", "error");
    } finally {
       setIsGeocoding(false);
    }
  };

  // Automatic Difficulty Suggestion
  useEffect(() => {
    if (selectedGroup?.name === 'Muntanya i Natura' || selectedGroup?.name === 'Esport i Benestar') {
      const dist = parseFloat(formData.distance) || 0;
      const elev = parseFloat(formData.elevation) || 0;

      let suggestion = "";
      if (dist === 0 && elev === 0) suggestion = "";
      else if (dist < 5 && elev < 200) suggestion = "Fàcil / Familiar";
      else if (dist < 12 && elev < 600) suggestion = "Moderat";
      else if (dist < 20 && elev < 1200) suggestion = "Exigent";
      else suggestion = "Molt Exigent / Expert";

      if (suggestion && formData.difficulty === "") {
        setFormData(prev => ({ ...prev, difficulty: suggestion }));
      }
    }
  }, [formData.distance, formData.elevation, selectedGroup]);

  if (!isOpen || !mounted) return null;

  return createPortal(
    <div className="fixed inset-0 z-[9999] flex justify-center md:justify-end items-stretch p-0">
      {toast && (
        <Toast 
          message={toast.message} 
          type={toast.type} 
          onClose={() => setToast(null)} 
        />
      )}
      {/* Backdrop (Invisible but captures clicks to close) */}
      <div className="absolute inset-0 bg-black/10 transition-opacity duration-500" onClick={onClose} />

      {/* Drawer / Modal Content */}
      <div 
        onClick={(e) => e.stopPropagation()}
        className="relative w-full md:w-[450px] lg:w-[500px] flex flex-col bg-[var(--color-surface)] border border-[var(--color-border)] md:border-y-0 md:border-r-0 md:border-l rounded-none md:rounded-l-3xl md:rounded-r-none overflow-hidden shadow-2xl animate-in slide-in-from-bottom-10 md:slide-in-from-right-full duration-300 h-full md:max-h-screen"
      >

        {/* Header */}
        <div className="p-8 border-b border-[var(--color-border)] flex justify-between items-center bg-[var(--color-surface-2)]/50">
           <div>
              <h3 className="text-xl font-display font-black tracking-tight flex items-center gap-2">
                {step === 'group' && "Tria un Grup"}
                {step === 'category' && `Explora ${selectedGroup?.name}`}
                {step === 'details' && `Detalls de l'Activitat`}
              </h3>
              <p className="text-[10px] text-[var(--color-muted)] uppercase font-black tracking-widest mt-1">
                {step === 'group' && "Pas 1 de 3"}
                {step === 'category' && "Pas 2 de 3"}
                {step === 'details' && "Pas 3 de 3 · " + selectedCategory?.name}
              </p>
           </div>
           <button 
             type="button"
             onClick={onClose} 
             className="p-2 hover:bg-[var(--color-surface-2)] rounded-full transition-colors"
           >
              <X size={20} />
           </button>
        </div>

        {/* Body */}
        <div className="p-6 md:p-8 flex-1 overflow-y-auto">
          {/* STEP 1: SELECT GROUP */}
          {step === 'group' && (
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
               {groups.map(g => {
                 const IconComponent = ICON_MAP[g.icon_key] || Plus;
                 return (
                   <button 
                    key={g.id}
                    onClick={() => { setSelectedGroup(g); setStep('category'); }}
                    className="flex flex-col items-center gap-4 p-6 rounded-3xl border border-[var(--color-border)] bg-[var(--color-bg)] hover:border-[var(--color-accent)] hover:bg-[var(--color-accent-subtle)]/5 transition-all group"
                   >
                      <div 
                        className="w-12 h-12 rounded-full flex items-center justify-center text-white shadow-xl transition-transform group-hover:scale-110"
                        style={{ backgroundColor: g.accent_color }}
                      >
                         <IconComponent size={20} />
                      </div>
                      <span className="text-xs font-bold text-center leading-tight">{g.name}</span>
                   </button>
                 );
               })}
            </div>
          )}

          {/* STEP 2: SELECT CATEGORY */}
          {step === 'category' && (
            <div className="space-y-6">
               <div className="flex gap-2">
                 <div className="relative flex-1">
                   <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-[var(--color-muted)]" size={18} />
                   <input 
                     type="text" 
                     autoFocus
                     value={search}
                     onChange={e => setSearch(e.target.value)}
                     placeholder="Cerca una categoria..." 
                     className="w-full bg-[var(--color-surface-2)] border border-[var(--color-border)] rounded-2xl pl-12 pr-4 py-4 text-sm outline-none focus:border-[var(--color-accent)] transition-all"
                   />
                 </div>
                 <button 
                  onClick={() => { setIsAddingCategory(true); setEditingCategoryId(null); setCategoryName(""); }}
                  className="p-4 bg-[var(--color-accent)] text-white rounded-2xl hover:scale-105 transition-all shadow-lg shadow-[var(--color-accent-glow)]"
                 >
                   <Plus size={24} />
                 </button>
               </div>

               {isAddingCategory || editingCategoryId ? (
                 <div className="bg-[var(--color-surface-2)] p-6 rounded-3xl border border-[var(--color-accent)]/30 space-y-4 animate-in zoom-in-95">
                    <div className="flex justify-between items-center">
                       <h4 className="text-xs font-black uppercase tracking-widest text-[var(--color-accent)]">
