                    {isManagingSubs ? (
                      <div className="bg-[var(--color-surface-2)] p-4 rounded-2xl border border-[var(--color-accent)]/20 space-y-3 animate-in fade-in slide-in-from-top-2">
                        <div className="flex gap-2">
                          <input 
                            type="text"
                            placeholder="Nova subcategoria..."
