                             type="button" 
                             onClick={() => setIsMapOpen(true)}
                             className="absolute right-2 top-1/2 -translate-y-1/2 p-2.5 text-[var(--color-accent)] hover:bg-[var(--color-accent)]/10 rounded-xl transition-all hover:scale-110 active:scale-95"
