                           >
                              <Map size={16} />
                           </button>
                       </div>
                     </div>
                     <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-2">
                          <label className="text-[10px] uppercase font-black tracking-widest text-[var(--color-muted)]">Latitud (Opcional)</label>
